import { getApiBase } from './platform';

const API_BASE = getApiBase();

// ── Retry configuration ────────────────────────────────────────────────────
const MAX_RETRIES = 3;
const RETRY_DELAYS = [1000, 2000, 4000]; // exponential backoff

const sleep = (ms) => new Promise(resolve => setTimeout(resolve, ms));

// ── Global connection health tracking ──────────────────────────────────────
// Components can subscribe to connection state changes via window events.
let _connectionHealthy = true;
let _consecutiveFailures = 0;

function reportApiSuccess() {
  _consecutiveFailures = 0;
  if (!_connectionHealthy) {
    _connectionHealthy = true;
    window.dispatchEvent(new CustomEvent('aura:connection-change', { detail: { healthy: true } }));
  }
}

function reportApiFailure(error) {
  _consecutiveFailures++;
  if (_consecutiveFailures >= 2 && _connectionHealthy) {
    _connectionHealthy = false;
    window.dispatchEvent(new CustomEvent('aura:connection-change', { detail: { healthy: false, error: error?.message } }));
  }
}

/** Check current connection health (for components that mount after events fire) */
export function isApiHealthy() {
  return _connectionHealthy;
}

// ── Toast dispatch helper ──────────────────────────────────────────────────
// Dispatches a custom event that the ToastProvider can listen to,
// so api.js doesn't need to import React context directly.
let _lastToastTime = 0;
function emitToast(type, title, message) {
  // Throttle: don't spam toasts (max 1 per 5 seconds)
  const now = Date.now();
  if (now - _lastToastTime < 5000) return;
  _lastToastTime = now;
  window.dispatchEvent(new CustomEvent('aura:api-toast', { detail: { type, title, message } }));
}

let _refreshPromise = null; // singleton to avoid concurrent refresh attempts

function authHeaders() {
  const token = localStorage.getItem('aura_token');
  return token ? { Authorization: `Bearer ${token}` } : {};
}

async function tryRefreshToken() {
  // Only one refresh at a time — concurrent callers share the same promise
  if (_refreshPromise) return _refreshPromise;

  _refreshPromise = (async () => {
    const refreshToken = localStorage.getItem('aura_refresh_token');
    if (!refreshToken) return false;

    try {
      const r = await fetch(`${API_BASE}/auth/refresh`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ refresh_token: refreshToken }),
      });
      if (!r.ok) return false;

      const data = await r.json();
      if (data.access_token) {
        localStorage.setItem('aura_token', data.access_token);
        if (data.refresh_token) {
          localStorage.setItem('aura_refresh_token', data.refresh_token);
        }
        return true;
      }
      return false;
    } catch {
      return false;
    }
  })();

  try {
    return await _refreshPromise;
  } finally {
    _refreshPromise = null;
  }
}

function logout() {
  localStorage.removeItem('aura_token');
  localStorage.removeItem('aura_refresh_token');
  localStorage.removeItem('aura_user');
  window.location.href = '/login';
}

// ── In-flight request deduplication for GET requests ──
// If the same GET path is already in-flight, reuse the promise instead of making a duplicate request.
const _inflight = new Map();

export async function api(path, options = {}) {
  const { silent, signal, ...fetchOpts } = options;
  const isGet = !fetchOpts.method || fetchOpts.method === 'GET';

  // Deduplicate concurrent GET requests to the same path
  if (isGet && _inflight.has(path)) {
    try { return await _inflight.get(path); } catch { return null; }
  }

  const promise = _apiInner(path, options);
  if (isGet) {
    _inflight.set(path, promise);
    promise.finally(() => _inflight.delete(path));
  }
  return promise;
}

async function _apiInner(path, options = {}) {
  const { silent, signal, ...fetchOpts } = options;
  const buildFetchOptions = () => ({
    headers: { 'Content-Type': 'application/json', ...authHeaders(), ...fetchOpts.headers },
    ...fetchOpts,
    ...(signal ? { signal } : {}),
  });

  let lastError;
  // 3 retries for GET, 1 attempt for mutations (POST/PUT/DELETE are NOT idempotent)
  const isGet = !fetchOpts.method || fetchOpts.method === 'GET';
  const maxRetries = isGet ? MAX_RETRIES : 0;

  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    try {
      const r = await fetch(`${API_BASE}${path}`, buildFetchOptions());

      // ── 401 Unauthorized: try token refresh, then logout ──
      if (r.status === 401) {
        if (silent) return null;

        const refreshed = await tryRefreshToken();
        if (refreshed) {
          const retry = await fetch(`${API_BASE}${path}`, buildFetchOptions());
          if (retry.ok) {
            const rct = retry.headers.get('content-type') || '';
            if (!rct.includes('application/json')) throw new Error('Non-JSON response');
            reportApiSuccess();
            return await retry.json();
          }
        }

        logout();
        return null;
      }

      // ── 429 Too Many Requests: respect Retry-After header ──
      if (r.status === 429) {
        const retryAfter = r.headers.get('Retry-After');
        const waitMs = retryAfter
          ? (isNaN(retryAfter) ? 5000 : parseInt(retryAfter, 10) * 1000)
          : 5000;
        if (attempt < maxRetries) {
          if (!silent) emitToast('warning', 'Rate limited', `Retrying in ${Math.ceil(waitMs / 1000)}s...`);
          await sleep(Math.min(waitMs, 30000)); // cap at 30s
          continue;
        }
        if (!silent) emitToast('warning', 'Rate limited', 'Too many requests. Please wait a moment.');
        throw new Error(`429 Too Many Requests`);
      }

      // ── 502/503 Service Unavailable: retry with backoff ──
      if ((r.status === 502 || r.status === 503) && attempt < maxRetries) {
        lastError = new Error(`${r.status} ${r.statusText}`);
        reportApiFailure(lastError);
        await sleep(RETRY_DELAYS[attempt] || 4000);
        continue;
      }

      // ── 403 Tier Gate: show upgrade prompt instead of generic error ──
      if (r.status === 403) {
        const requiredTier = r.headers.get('X-Required-Tier');
        const userTier = r.headers.get('X-User-Tier');
        let detail = '';
        try { detail = (await r.json()).detail || ''; } catch {}
        const tierLabel = { starter: 'Starter', trader: 'Trader', active: 'Active Trader', pro: 'Pro', elite: 'Elite', institutional: 'Institutional' }[requiredTier] || requiredTier;
        if (requiredTier) {
          if (!silent) emitToast('warning', 'Upgrade Required', `This feature requires ${tierLabel} tier. Upgrade at auraalpha.cc/pricing`);
          const err = new Error(detail || `Requires ${tierLabel} tier`);
          err.status = 403;
          err.requiredTier = requiredTier;
          err.userTier = userTier;
          throw err;
        }
        throw new Error(detail || `${r.status} ${r.statusText}`);
      }

      // ── Other errors ──
      if (!r.ok) {
        const errMsg = `${r.status} ${r.statusText}`;
        throw new Error(errMsg);
      }

      // Guard against non-JSON responses (e.g. nginx 502/503 returning HTML)
      const ct = r.headers.get('content-type') || '';
      if (!ct.includes('application/json')) {
        if (attempt < maxRetries) {
          lastError = new Error('Non-JSON response from server');
          reportApiFailure(lastError);
          await sleep(RETRY_DELAYS[attempt] || 4000);
          continue;
        }
        throw new Error('Non-JSON response from server');
      }

      // Success
      reportApiSuccess();
      return await r.json();

    } catch (e) {
      if (e.name === 'AbortError') return null; // request cancelled, don't warn
      lastError = e;

      // Network error (offline, DNS failure, CORS, etc.)
      const isNetworkError = e.message === 'Failed to fetch' ||
                             e.message === 'NetworkError when attempting to fetch resource.' ||
                             e.message === 'Network request failed' ||
                             e.name === 'TypeError';

      if (isNetworkError) {
        reportApiFailure(e);
      }

      if (attempt < maxRetries) {
        await sleep(RETRY_DELAYS[attempt] || 4000);
        continue;
      }

      // All retries exhausted
      if (isNetworkError && !silent) {
        emitToast('error', 'Connection lost', 'Unable to reach the server. Check your connection.');
      }
    }
  }

  console.warn(`[API] ${path} failed after ${maxRetries + 1} attempts:`, lastError?.message);
  if (!options.silent && lastError) {
    reportApiFailure(lastError);
  }
  return null;
}

export async function apiPost(path, body) {
  return api(path, { method: 'POST', body: JSON.stringify(body) });
}

export async function apiPut(path, body) {
  return api(path, { method: 'PUT', body: JSON.stringify(body) });
}

export async function apiDelete(path) {
  return api(path, { method: 'DELETE' });
}
