/* ═══════════════════════════════════════════════════════════════════════════
   AURA ALPHA — Notification Bell
   Bell icon with unread count badge + dropdown showing last 10 notifications.
   Types: signal, alert, system, trade, promotion
   Polls /api/notifications or falls back to aggregating from other endpoints.
   ═══════════════════════════════════════════════════════════════════════════ */
import { useState, useEffect, useRef, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { getApiBase } from '../utils/platform';

const POLL_INTERVAL = 30_000; // 30s
const MAX_DISPLAY = 10;

const COLORS = {
  bg: '#0D1117',
  surface: '#161B22',
  surface2: '#1C2128',
  border: '#30363D',
  text: '#E6EDF3',
  textSec: '#8B949E',
  green: '#3FB950',
  red: '#F85149',
  blue: '#58A6FF',
  amber: '#D29922',
  purple: '#BC8CFF',
};

const TYPE_CONFIG = {
  signal:    { color: COLORS.blue,   label: 'Signal',    icon: 'M13 2L4.5 12.5h5.5l-1.5 9.5 9-11h-6z' },
  alert:     { color: COLORS.amber,  label: 'Alert',     icon: 'M10.29 3.86L1.82 18a2 2 0 001.71 3h16.94a2 2 0 001.71-3L13.71 3.86a2 2 0 00-3.42 0z' },
  trade:     { color: COLORS.green,  label: 'Trade',     icon: 'M12 2v20M2 12h20' },
  promotion: { color: COLORS.purple, label: 'Promotion', icon: 'M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z' },
  system:    { color: COLORS.textSec, label: 'System',   icon: 'M12 22c5.5 0 10-4.5 10-10S17.5 2 12 2 2 6.5 2 12s4.5 10 10 10zM12 8v4M12 16h.01' },
  // Competition / gamification notification types
  achievement_unlocked: { color: COLORS.amber,  label: 'Achievement', icon: 'M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z' },
  rank_changed:         { color: COLORS.green,  label: 'Rank',        icon: 'M23 6l-9.5 9.5-5-5L1 18' },
  xp_awarded:           { color: COLORS.purple, label: 'XP',          icon: 'M13 2L4.5 12.5h5.5l-1.5 9.5 9-11h-6z' },
  tier_changed:         { color: COLORS.blue,   label: 'Tier',        icon: 'M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z' },
  streak_milestone:     { color: COLORS.amber,  label: 'Streak',      icon: 'M12 2c-1 4-4 6-4 10a4 4 0 008 0c0-4-3-6-4-10z' },
  tournament:           { color: COLORS.blue,   label: 'Tournament',  icon: 'M6 9H4.5a2.5 2.5 0 010-5H6M18 9h1.5a2.5 2.5 0 000-5H18M4 22h16M10 14.66V17c0 .55-.47.98-.97 1.21C7.85 18.75 7 20 7 22M14 14.66V17c0 .55.47.98.97 1.21C16.15 18.75 17 20 17 22M18 2H6v7a6 6 0 0012 0V2z' },
};

function TypeIcon({ type, size = 14 }) {
  const cfg = TYPE_CONFIG[type] || TYPE_CONFIG.system;
  return (
    <svg width={size} height={size} viewBox="0 0 24 24" fill="none"
      stroke={cfg.color} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"
      style={{ flexShrink: 0 }}
    >
      <path d={cfg.icon} />
    </svg>
  );
}

function timeAgo(ts) {
  if (!ts) return '';
  const diff = Date.now() - new Date(ts).getTime();
  if (diff < 60_000) return 'just now';
  if (diff < 3600_000) return `${Math.floor(diff / 60_000)}m ago`;
  if (diff < 86400_000) return `${Math.floor(diff / 3600_000)}h ago`;
  return `${Math.floor(diff / 86400_000)}d ago`;
}

export default function NotificationBell() {
  const navigate = useNavigate();
  const [notifications, setNotifications] = useState([]);
  const [open, setOpen] = useState(false);
  const [clearedAt, setClearedAt] = useState(() => {
    try { return localStorage.getItem('aura_notif_cleared_at') || ''; } catch { return ''; }
  });
  const [readIds, setReadIds] = useState(() => {
    try {
      return new Set(JSON.parse(localStorage.getItem('aura_notif_read') || '[]'));
    } catch { return new Set(); }
  });
  const dropdownRef = useRef(null);

  // Persist read IDs
  useEffect(() => {
    localStorage.setItem('aura_notif_read', JSON.stringify([...readIds]));
  }, [readIds]);

  // Close dropdown on outside click
  useEffect(() => {
    if (!open) return;
    const handler = (e) => {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target)) {
        setOpen(false);
      }
    };
    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, [open]);

  // Fetch notifications
  const fetchNotifications = useCallback(async () => {
    const token = localStorage.getItem('aura_token') || '';
    const headers = { Authorization: `Bearer ${token}` };
    const base = getApiBase();
    const items = [];

    try {
      // Try dedicated notifications endpoint first
      const res = await fetch(`${base}/notifications/recent`, { headers });
      if (res.ok) {
        const data = await res.json();
        if (Array.isArray(data?.notifications)) {
          // Also merge competition notifications into the main feed
          const merged = [...data.notifications];
          try {
            const compRes = await fetch(`${base}/competition/notifications?limit=10`, { headers });
            if (compRes.ok) {
              const compData = await compRes.json();
              if (Array.isArray(compData?.notifications)) {
                const COMP_ROUTE_MAP = {
                  achievement_unlocked: '/achievements',
                  rank_changed: '/leaderboard',
                  tournament: '/tournaments',
                  xp_awarded: '/achievements',
                  tier_changed: '/achievements',
                  streak_milestone: '/achievements',
                };
                compData.notifications.forEach(cn => {
                  // Avoid duplicates by id
                  if (!merged.some(m => m.id === cn.id)) {
                    merged.push({
                      id: cn.id || `comp-${cn.type}-${cn.created_at}`,
                      type: cn.type || 'system',
                      title: cn.title || cn.type,
                      body: cn.body || '',
                      timestamp: cn.created_at || cn.timestamp || new Date().toISOString(),
                      path: COMP_ROUTE_MAP[cn.type] || '/achievements',
                    });
                  }
                });
              }
            }
          } catch { /* silently fail comp fetch */ }
          merged.sort((a, b) => new Date(b.timestamp || 0) - new Date(a.timestamp || 0));
          // Filter out notifications older than the last "mark all read" timestamp
          const cleared = clearedAt ? new Date(clearedAt).getTime() : 0;
          const filtered = cleared ? merged.filter(n => new Date(n.timestamp || 0).getTime() > cleared) : merged;
          setNotifications(filtered.slice(0, MAX_DISPLAY));
          return;
        }
      }
    } catch { /* fallback below */ }

    // Fallback: aggregate from signals + alerts
    try {
      const [sigRes, alertRes] = await Promise.allSettled([
        fetch(`${base}/signals/latest?promoted_only=true`, { headers }).then(r => r.ok ? r.json() : null),
        fetch(`${base}/alerts/triggered`, { headers }).then(r => r.ok ? r.json() : null),
      ]);

      if (sigRes.status === 'fulfilled' && sigRes.value?.signals) {
        sigRes.value.signals.slice(0, 5).forEach((sig, i) => {
          items.push({
            id: `sig-${sig.symbol || i}-${sig.strategy || ''}`,
            type: 'signal',
            title: `${sig.direction || 'Signal'}: ${sig.symbol || 'Unknown'}`,
            body: `Strategy: ${sig.strategy || '?'} | Confidence: ${sig.confidence ? (sig.confidence * 100).toFixed(0) + '%' : '?'}`,
            timestamp: sig.timestamp || sig.generated_at || new Date().toISOString(),
            path: '/signals',
          });
        });
      }

      if (alertRes.status === 'fulfilled') {
        const alerts = Array.isArray(alertRes.value) ? alertRes.value : (alertRes.value?.alerts || []);
        alerts.slice(0, 5).forEach((al, i) => {
          items.push({
            id: `alert-${al.id || i}`,
            type: 'alert',
            title: `Alert: ${al.symbol || 'Unknown'}`,
            body: al.message || `${al.condition || 'triggered'}`,
            timestamp: al.triggered_at || al.timestamp || new Date().toISOString(),
            path: '/alerts',
          });
        });
      }
    } catch { /* silently fail */ }

    // Also fetch competition/gamification notifications
    try {
      const compRes = await fetch(`${base}/competition/notifications?limit=10`, { headers });
      if (compRes.ok) {
        const compData = await compRes.json();
        if (Array.isArray(compData?.notifications)) {
          const COMP_ROUTE_MAP = {
            achievement_unlocked: '/achievements',
            rank_changed: '/leaderboard',
            tournament: '/tournaments',
            xp_awarded: '/achievements',
            tier_changed: '/achievements',
            streak_milestone: '/achievements',
          };
          compData.notifications.forEach(cn => {
            items.push({
              id: cn.id || `comp-${cn.type}-${cn.created_at}`,
              type: cn.type || 'system',
              title: cn.title || cn.type,
              body: cn.body || '',
              timestamp: cn.created_at || cn.timestamp || new Date().toISOString(),
              path: COMP_ROUTE_MAP[cn.type] || '/achievements',
            });
          });
        }
      }
    } catch { /* silently fail */ }

    // Sort by timestamp desc, filter out cleared
    items.sort((a, b) => new Date(b.timestamp) - new Date(a.timestamp));
    const cleared = clearedAt ? new Date(clearedAt).getTime() : 0;
    const filtered = cleared ? items.filter(n => new Date(n.timestamp || 0).getTime() > cleared) : items;
    setNotifications(filtered.slice(0, MAX_DISPLAY));
  }, []);

  useEffect(() => {
    fetchNotifications();
    const iv = setInterval(fetchNotifications, POLL_INTERVAL);
    return () => clearInterval(iv);
  }, [fetchNotifications]);

  const unreadCount = notifications.filter(n => !readIds.has(n.id)).length;

  const markAsRead = (id) => {
    setReadIds(prev => new Set([...prev, id]));
  };

  const markAllRead = () => {
    setReadIds(new Set(notifications.map(n => n.id)));
    const now = new Date().toISOString();
    setClearedAt(now);
    localStorage.setItem('aura_notif_cleared_at', now);
    setNotifications([]);
  };

  const handleItemClick = (notif) => {
    markAsRead(notif.id);
    setOpen(false);
    if (notif.path) navigate(notif.path);
  };

  return (
    <div ref={dropdownRef} style={{ position: 'relative' }}>
      {/* Bell button */}
      <button
        className="topbar-icon-btn"
        title="Notifications"
        aria-label={`Notifications${unreadCount > 0 ? ` (${unreadCount} unread)` : ''}`}
        onClick={() => setOpen(o => !o)}
        style={{ position: 'relative' }}
      >
        <svg viewBox="0 0 24 24" style={{ width: 16, height: 16, fill: 'none', stroke: 'currentColor', strokeWidth: 1.8, strokeLinecap: 'round', strokeLinejoin: 'round' }}>
          <path d="M18 8A6 6 0 006 8c0 7-3 9-3 9h18s-3-2-3-9" />
          <path d="M13.73 21a2 2 0 01-3.46 0" />
        </svg>
        {unreadCount > 0 && (
          <span style={{
            position: 'absolute',
            top: 2,
            right: 2,
            minWidth: 16,
            height: 16,
            borderRadius: 8,
            background: COLORS.red,
            color: '#fff',
            fontSize: 9,
            fontWeight: 700,
            fontFamily: "'JetBrains Mono', monospace",
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            padding: '0 4px',
            boxShadow: `0 0 6px ${COLORS.red}60`,
            lineHeight: 1,
          }}>
            {unreadCount > 99 ? '99+' : unreadCount}
          </span>
        )}
      </button>

      {/* Dropdown */}
      {open && (
        <div style={{
          position: 'absolute',
          top: 'calc(100% + 8px)',
          right: 0,
          width: 380,
          maxHeight: 480,
          backgroundColor: COLORS.surface,
          border: `1px solid ${COLORS.border}`,
          borderRadius: 14,
          boxShadow: '0 12px 48px rgba(0,0,0,0.5)',
          zIndex: 9000,
          overflow: 'hidden',
          display: 'flex',
          flexDirection: 'column',
        }}>
          {/* Header */}
          <div style={{
            padding: '14px 18px',
            borderBottom: `1px solid ${COLORS.border}`,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'space-between',
          }}>
            <span style={{
              fontSize: 14,
              fontWeight: 700,
              color: COLORS.text,
              fontFamily: "'Plus Jakarta Sans', system-ui, sans-serif",
            }}>
              Notifications
            </span>
            {unreadCount > 0 && (
              <button
                onClick={markAllRead}
                style={{
                  background: 'none',
                  border: 'none',
                  color: COLORS.blue,
                  fontSize: 12,
                  fontWeight: 600,
                  cursor: 'pointer',
                  fontFamily: "'Plus Jakarta Sans', system-ui, sans-serif",
                  padding: '2px 6px',
                  borderRadius: 6,
                  transition: 'background 200ms',
                }}
                onMouseEnter={e => e.currentTarget.style.background = `${COLORS.blue}15`}
                onMouseLeave={e => e.currentTarget.style.background = 'none'}
              >
                Mark all read
              </button>
            )}
          </div>

          {/* Items */}
          <div style={{ flex: 1, overflowY: 'auto', minHeight: 0 }}>
            {notifications.length === 0 ? (
              <div style={{
                padding: '40px 20px',
                textAlign: 'center',
                color: COLORS.textSec,
                fontSize: 13,
              }}>
                <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="#484F58" strokeWidth="1.5"
                  strokeLinecap="round" strokeLinejoin="round" style={{ margin: '0 auto 12px', display: 'block' }}>
                  <path d="M18 8A6 6 0 006 8c0 7-3 9-3 9h18s-3-2-3-9" />
                  <path d="M13.73 21a2 2 0 01-3.46 0" />
                </svg>
                No notifications yet
              </div>
            ) : (
              notifications.map(notif => {
                const isRead = readIds.has(notif.id);
                const cfg = TYPE_CONFIG[notif.type] || TYPE_CONFIG.system;
                return (
                  <button
                    key={notif.id}
                    onClick={() => handleItemClick(notif)}
                    style={{
                      display: 'flex',
                      gap: 12,
                      padding: '12px 18px',
                      width: '100%',
                      textAlign: 'left',
                      background: isRead ? 'transparent' : `${COLORS.blue}06`,
                      border: 'none',
                      borderBottom: `1px solid ${COLORS.border}`,
                      cursor: 'pointer',
                      transition: 'background 200ms',
                      fontFamily: "'Plus Jakarta Sans', system-ui, sans-serif",
                    }}
                    onMouseEnter={e => e.currentTarget.style.background = `${COLORS.blue}10`}
                    onMouseLeave={e => e.currentTarget.style.background = isRead ? 'transparent' : `${COLORS.blue}06`}
                  >
                    {/* Icon */}
                    <div style={{
                      width: 32,
                      height: 32,
                      borderRadius: 8,
                      backgroundColor: `${cfg.color}15`,
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      flexShrink: 0,
                      marginTop: 2,
                    }}>
                      <TypeIcon type={notif.type} size={14} />
                    </div>

                    {/* Content */}
                    <div style={{ flex: 1, minWidth: 0 }}>
                      <div style={{
                        display: 'flex',
                        alignItems: 'center',
                        gap: 8,
                        marginBottom: 2,
                      }}>
                        <span style={{
                          fontSize: 13,
                          fontWeight: isRead ? 500 : 600,
                          color: COLORS.text,
                          overflow: 'hidden',
                          textOverflow: 'ellipsis',
                          whiteSpace: 'nowrap',
                        }}>
                          {notif.title}
                        </span>
                        {!isRead && (
                          <span style={{
                            width: 6,
                            height: 6,
                            borderRadius: '50%',
                            backgroundColor: COLORS.blue,
                            flexShrink: 0,
                          }} />
                        )}
                      </div>
                      <div style={{
                        fontSize: 12,
                        color: COLORS.textSec,
                        overflow: 'hidden',
                        textOverflow: 'ellipsis',
                        whiteSpace: 'nowrap',
                        lineHeight: 1.4,
                      }}>
                        {notif.body}
                      </div>
                      <div style={{
                        fontSize: 10,
                        color: '#484F58',
                        marginTop: 4,
                        fontFamily: "'JetBrains Mono', monospace",
                      }}>
                        {timeAgo(notif.timestamp)}
                      </div>
                    </div>
                  </button>
                );
              })
            )}
          </div>

          {/* Footer */}
          <button
            onClick={() => { setOpen(false); navigate('/notifications'); }}
            style={{
              padding: '12px 18px',
              borderTop: `1px solid ${COLORS.border}`,
              background: 'none',
              border: 'none',
              borderTopStyle: 'solid',
              borderTopWidth: 1,
              borderTopColor: COLORS.border,
              color: COLORS.blue,
              fontSize: 12,
              fontWeight: 600,
              cursor: 'pointer',
              textAlign: 'center',
              width: '100%',
              fontFamily: "'Plus Jakarta Sans', system-ui, sans-serif",
              transition: 'background 200ms',
            }}
            onMouseEnter={e => e.currentTarget.style.background = `${COLORS.blue}08`}
            onMouseLeave={e => e.currentTarget.style.background = 'none'}
          >
            View All Notifications
          </button>
        </div>
      )}
    </div>
  );
}
