/**
 * AURA ALPHA -- PlatformGate
 *
 * Wraps route elements to enforce iOS page restrictions.
 * If the current route is not available on iOS, shows a
 * "Available on desktop" message instead of the page content.
 *
 * Usage in router:
 *   <Route path="/ml-analytics" element={
 *     <PlatformGate><MLAnalyticsPage /></PlatformGate>
 *   } />
 *
 * Or wrap an entire route group:
 *   <Route element={<PlatformGate />}>  // uses <Outlet />
 *     <Route path="/ml-analytics" element={<MLAnalyticsPage />} />
 *   </Route>
 */
import { useLocation, useNavigate, Outlet } from 'react-router-dom';
import { isPageAvailable, isIOS } from '../config/platform';

export default function PlatformGate({ children }) {
  const location = useLocation();
  const navigate = useNavigate();

  // On web/desktop, always pass through
  if (!isIOS) {
    return children || <Outlet />;
  }

  // On iOS, check if this route is allowed
  if (isPageAvailable(location.pathname)) {
    return children || <Outlet />;
  }

  // Blocked -- show desktop-only message
  return (
    <div
      style={{
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        justifyContent: 'center',
        height: '70vh',
        gap: 16,
        padding: 32,
        textAlign: 'center',
        fontFamily: "'Plus Jakarta Sans', sans-serif",
      }}
    >
      <div
        style={{
          width: 64,
          height: 64,
          borderRadius: 14,
          background: 'rgba(88, 166, 255, 0.1)',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          fontSize: 28,
        }}
      >
        {/* Desktop monitor icon (plain text, no emoji) */}
        <svg
          width="28"
          height="28"
          viewBox="0 0 24 24"
          fill="none"
          stroke="#60A5FA"
          strokeWidth="2"
          strokeLinecap="round"
          strokeLinejoin="round"
        >
          <rect x="2" y="3" width="20" height="14" rx="2" ry="2" />
          <line x1="8" y1="21" x2="16" y2="21" />
          <line x1="12" y1="17" x2="12" y2="21" />
        </svg>
      </div>

      <div style={{ fontSize: 18, fontWeight: 700, color: '#E6EDF3' }}>
        Available on Desktop
      </div>

      <div
        style={{
          fontSize: 14,
          color: '#8B949E',
          maxWidth: 320,
          lineHeight: 1.6,
        }}
      >
        This feature is part of the full Aura Alpha desktop experience.
        Open auraalpha.cc in a browser for access to all 87+ pages.
      </div>

      <button
        onClick={() => navigate('/')}
        style={{
          marginTop: 8,
          padding: '10px 28px',
          borderRadius: 10,
          border: '1px solid #30363D',
          background: '#161B22',
          color: '#60A5FA',
          fontSize: 14,
          fontWeight: 600,
          cursor: 'pointer',
          fontFamily: "'Plus Jakarta Sans', sans-serif",
        }}
      >
        Back to Dashboard
      </button>
    </div>
  );
}
