import { Capacitor } from '@capacitor/core';

export function isNative() {
  try {
    return Capacitor.isNativePlatform();
  } catch {
    return false;
  }
}

export function isTauri() {
  return typeof window !== 'undefined' && !!window.__TAURI_INTERNALS__;
}

// Standalone mode: Tauri desktop app uses local API first, falls back to cloud
const LOCAL_API = 'http://127.0.0.1:8020/api';
const CLOUD_API = 'https://auraalpha.cc/api';

export function getApiBase() {
  if (isTauri()) return CLOUD_API;  // WebView is a real browser, can reach cloud directly
  if (isNative()) return CLOUD_API;
  return '/api';  // web: relative path, nginx proxies
}

export function getCloudApiBase() {
  return CLOUD_API;
}
