/**
 * useMLTracker — Aura Alpha ML event tracker
 *
 * Batches user interaction events and sends them to POST /api/ml/events
 * for ML model training (strategy recommender, risk scorer, signal quality,
 * regime classifier).
 *
 * Usage:
 *   const { track, flush } = useMLTracker()
 *   track('strategy_view', { strategy_name: 'Breakout', region: 'us' })
 *
 * Auto-flushes every 30 seconds and on page unload.
 * Session ID is stored in sessionStorage so it persists across navigations
 * but resets on new tabs/browser sessions.
 */

import { useEffect, useRef, useCallback } from 'react';
import { apiPost } from '../utils/api';

const FLUSH_INTERVAL_MS = 30_000;
const MAX_QUEUE_SIZE = 50;     // force-flush if queue exceeds this
const SESSION_KEY = 'aura_ml_session_id';

function _getOrCreateSessionId() {
  let sid = sessionStorage.getItem(SESSION_KEY);
  if (!sid) {
    sid = `${Date.now()}-${Math.random().toString(36).slice(2, 9)}`;
    sessionStorage.setItem(SESSION_KEY, sid);
  }
  return sid;
}

/**
 * Singleton event queue shared across all hook instances.
 * This avoids double-registering flush intervals when multiple
 * components mount the hook simultaneously.
 */
const _queue = [];
let _flushTimer = null;
let _sessionId = null;

async function _flush() {
  if (_queue.length === 0) return;
  const batch = _queue.splice(0, _queue.length);
  try {
    // Fire-and-forget: ML data collection failures must never affect the UI
    await Promise.all(
      batch.map(evt =>
        apiPost('/ml/events', evt).catch(() => null)
      )
    );
  } catch (_) {
    // Silently swallow — do not surface ML errors to users
  }
}

function _enqueue(event) {
  _queue.push(event);
  if (_queue.length >= MAX_QUEUE_SIZE) {
    _flush();
  }
}

/**
 * useMLTracker hook
 *
 * Returns:
 *   track(eventType, payload?)  — queue a tracking event
 *   flush()                     — manually send all queued events now
 */
export function useMLTracker() {
  const mountedRef = useRef(true);

  useEffect(() => {
    // Ensure session ID is initialised
    if (!_sessionId) {
      _sessionId = _getOrCreateSessionId();
    }

    // Start auto-flush timer (only one timer across all hook instances)
    if (!_flushTimer) {
      _flushTimer = setInterval(_flush, FLUSH_INTERVAL_MS);
    }

    // Flush on page unload / tab close
    const handleUnload = () => _flush();
    window.addEventListener('beforeunload', handleUnload);
    window.addEventListener('visibilitychange', () => {
      if (document.visibilityState === 'hidden') _flush();
    });

    mountedRef.current = true;

    return () => {
      mountedRef.current = false;
      window.removeEventListener('beforeunload', handleUnload);
      // Don't clear the shared timer on unmount — other instances may still be active
    };
  }, []);

  const track = useCallback((eventType, payload = {}) => {
    if (!eventType) return;
    _enqueue({
      event_type: eventType,
      payload,
      session_id: _sessionId || _getOrCreateSessionId(),
      timestamp: Date.now() / 1000,
    });
  }, []);

  const flush = useCallback(() => {
    return _flush();
  }, []);

  return { track, flush };
}

/**
 * Standalone track function for use outside React components.
 * e.g. in route handlers or event callbacks.
 */
export function trackMLEvent(eventType, payload = {}) {
  if (!_sessionId) {
    _sessionId = _getOrCreateSessionId();
  }
  _enqueue({
    event_type: eventType,
    payload,
    session_id: _sessionId,
    timestamp: Date.now() / 1000,
  });
}

export default useMLTracker;
