import { Component, useState } from 'react';

/**
 * Top-level Error Boundary for Aura Alpha.
 * Catches unhandled render errors and shows a professional, branded fallback
 * instead of a black/blank screen.
 */
class ErrorBoundary extends Component {
  constructor(props) {
    super(props);
    this.state = { hasError: false, error: null, componentStack: null, sentryLoaded: false };
  }

  static getDerivedStateFromError(error) {
    return { hasError: true, error };
  }

  componentDidCatch(error, info) {
    console.error('ErrorBoundary caught:', error, info);
    // Store component stack for debugging
    if (info?.componentStack) {
      this.setState({ componentStack: info.componentStack });
    }
    // Report to Sentry/GlitchTip if configured
    try {
      import('@sentry/react').then(Sentry => {
        if (Sentry.isInitialized?.() || Sentry.getCurrentHub?.().getClient?.()) {
          Sentry.captureException(error, { extra: { componentStack: info?.componentStack } });
          this.setState({ sentryLoaded: true });
        }
      }).catch(() => {});
    } catch (_) { /* Sentry not available */ }
  }

  isChunkLoadError(error) {
    if (!error) return false;
    const msg = error.message || '';
    return (
      msg.includes('Failed to fetch dynamically imported module') ||
      msg.includes('Loading chunk') ||
      msg.includes('Loading CSS chunk') ||
      msg.includes('Importing a module script failed')
    );
  }

  handleReset = () => {
    // For chunk load errors, do a hard reload to get fresh index.html
    if (this.isChunkLoadError(this.state.error)) {
      window.location.reload();
      return;
    }
    this.setState({ hasError: false, error: null });
  };

  componentDidUpdate(_, prevState) {
    // Auto-reload once for chunk load errors (stale deployment)
    if (
      this.state.hasError &&
      !prevState.hasError &&
      this.isChunkLoadError(this.state.error)
    ) {
      const key = 'aura_chunk_reload';
      const last = sessionStorage.getItem(key);
      // Only auto-reload once per session to avoid loops
      if (!last || Date.now() - parseInt(last) > 30000) {
        sessionStorage.setItem(key, String(Date.now()));
        window.location.reload();
        return;
      }
    }
  }

  render() {
    if (this.state.hasError) {
      const isChunk = this.isChunkLoadError(this.state.error);
      return (
        <ErrorFallback
          isChunk={isChunk}
          error={this.state.error}
          componentStack={this.state.componentStack}
          sentryLoaded={this.state.sentryLoaded}
          onReset={this.handleReset}
        />
      );
    }
    return this.props.children;
  }
}

/* ── Functional fallback component (allows useState for collapsible details) ── */
function ErrorFallback({ isChunk, error, componentStack, sentryLoaded, onReset }) {
  const [showDetails, setShowDetails] = useState(false);

  const errorText = error?.message || error?.toString() || 'Unknown error';
  const stackText = error?.stack || '';

  return (
    <div style={{
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      height: '100vh',
      backgroundColor: '#0D1117',
      fontFamily: "'Plus Jakarta Sans', system-ui, sans-serif",
      padding: 24,
    }}>
      <div style={{
        textAlign: 'center',
        maxWidth: 480,
        width: '100%',
        padding: 40,
        borderRadius: 16,
        backgroundColor: '#161B22',
        border: '1px solid #30363D',
        boxShadow: '0 8px 32px rgba(0, 0, 0, 0.4)',
      }}>
        {/* Aura Alpha branding */}
        <div style={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          gap: 10,
          marginBottom: 28,
        }}>
          <div style={{
            width: 36,
            height: 36,
            borderRadius: 10,
            background: 'linear-gradient(135deg, #60A5FA, #A78BFA)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            flexShrink: 0,
          }}>
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="#ffffff" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
              <polygon points="12 2 2 7 12 12 22 7 12 2" />
              <polyline points="2 17 12 22 22 17" />
              <polyline points="2 12 12 17 22 12" />
            </svg>
          </div>
          <span style={{
            fontSize: 18,
            fontWeight: 700,
            letterSpacing: '-0.02em',
            background: 'linear-gradient(135deg, #60A5FA, #A78BFA)',
            WebkitBackgroundClip: 'text',
            WebkitTextFillColor: 'transparent',
          }}>
            Aura Alpha
          </span>
        </div>

        {/* Status icon */}
        <div style={{
          width: 56,
          height: 56,
          borderRadius: '50%',
          background: isChunk
            ? 'linear-gradient(135deg, rgba(96,165,250,0.15), rgba(167,139,250,0.15))'
            : 'linear-gradient(135deg, rgba(248,81,73,0.12), rgba(210,153,34,0.12))',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          margin: '0 auto 20px',
        }}>
          <svg width="26" height="26" viewBox="0 0 24 24" fill="none" stroke={isChunk ? '#60A5FA' : '#F85149'} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            {isChunk ? (
              <>
                <path d="M21 2l-2 2m-7.61 7.61a5.5 5.5 0 1 1-7.778 7.778 5.5 5.5 0 0 1 7.777-7.777zm0 0L15.5 7.5m0 0l3 3L22 7l-3-3m-3.5 3.5L19 4" />
              </>
            ) : (
              <>
                <circle cx="12" cy="12" r="10" />
                <line x1="12" y1="8" x2="12" y2="12" />
                <line x1="12" y1="16" x2="12.01" y2="16" />
              </>
            )}
          </svg>
        </div>

        {/* Title */}
        <h2 style={{
          color: '#E6EDF3',
          fontSize: 20,
          fontWeight: 700,
          margin: '0 0 8px 0',
          letterSpacing: '-0.01em',
        }}>
          {isChunk ? 'App Updated' : 'Something went wrong'}
        </h2>

        {/* Description */}
        <p style={{
          color: '#8B949E',
          fontSize: 14,
          margin: '0 0 8px 0',
          lineHeight: 1.6,
        }}>
          {isChunk
            ? 'A new version has been deployed. Click reload to get the latest.'
            : 'Our team has been notified and is looking into it. Your data is safe.'}
        </p>

        {/* Sentry auto-reported note */}
        {!isChunk && sentryLoaded && (
          <p style={{
            color: '#3FB950',
            fontSize: 12,
            margin: '0 0 24px 0',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            gap: 6,
          }}>
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#3FB950" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
              <polyline points="20 6 9 17 4 12" />
            </svg>
            Error has been automatically reported
          </p>
        )}

        {/* Spacer when no Sentry note */}
        {(!sentryLoaded || isChunk) && <div style={{ height: 16 }} />}

        {/* Action buttons */}
        <div style={{ display: 'flex', gap: 10, justifyContent: 'center', flexWrap: 'wrap', marginBottom: isChunk ? 0 : 20 }}>
          <button
            onClick={isChunk ? () => window.location.reload() : onReset}
            style={{
              padding: '10px 24px',
              borderRadius: 10,
              border: 'none',
              background: 'linear-gradient(135deg, #60A5FA, #A78BFA)',
              color: '#ffffff',
              fontSize: 13,
              fontWeight: 600,
              cursor: 'pointer',
              fontFamily: "'Plus Jakarta Sans', system-ui, sans-serif",
              boxShadow: '0 4px 16px rgba(96, 165, 250, 0.25)',
              transition: 'opacity 0.15s',
            }}
            onMouseEnter={e => e.currentTarget.style.opacity = '0.85'}
            onMouseLeave={e => e.currentTarget.style.opacity = '1'}
          >
            Reload Page
          </button>
          {!isChunk && (
            <>
              <button
                onClick={() => { window.location.href = '/'; }}
                style={{
                  padding: '10px 24px',
                  borderRadius: 10,
                  border: '1px solid #30363D',
                  background: 'transparent',
                  color: '#8B949E',
                  fontSize: 13,
                  fontWeight: 600,
                  cursor: 'pointer',
                  fontFamily: "'Plus Jakarta Sans', system-ui, sans-serif",
                  transition: 'border-color 0.15s, color 0.15s',
                }}
                onMouseEnter={e => { e.currentTarget.style.borderColor = '#8B949E'; e.currentTarget.style.color = '#E6EDF3'; }}
                onMouseLeave={e => { e.currentTarget.style.borderColor = '#30363D'; e.currentTarget.style.color = '#8B949E'; }}
              >
                Go Home
              </button>
              <a
                href={`mailto:support@auraalpha.cc?subject=Bug Report — Aura Alpha&body=Hi, I encountered an error on Aura Alpha.%0A%0APage: ${encodeURIComponent(window.location.href)}%0AError: ${encodeURIComponent(errorText)}%0A%0APlease describe what you were doing:%0A`}
                style={{
                  padding: '10px 24px',
                  borderRadius: 10,
                  border: '1px solid #30363D',
                  background: 'transparent',
                  color: '#8B949E',
                  fontSize: 13,
                  fontWeight: 600,
                  cursor: 'pointer',
                  fontFamily: "'Plus Jakarta Sans', system-ui, sans-serif",
                  textDecoration: 'none',
                  display: 'inline-flex',
                  alignItems: 'center',
                  gap: 6,
                  transition: 'border-color 0.15s, color 0.15s',
                }}
                onMouseEnter={e => { e.currentTarget.style.borderColor = '#8B949E'; e.currentTarget.style.color = '#E6EDF3'; }}
                onMouseLeave={e => { e.currentTarget.style.borderColor = '#30363D'; e.currentTarget.style.color = '#8B949E'; }}
              >
                <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                  <path d="M4 4h16c1.1 0 2 .9 2 2v12c0 1.1-.9 2-2 2H4c-1.1 0-2-.9-2-2V6c0-1.1.9-2 2-2z" />
                  <polyline points="22,6 12,13 2,6" />
                </svg>
                Report Issue
              </a>
            </>
          )}
        </div>

        {/* Collapsible error details */}
        {!isChunk && (
          <div style={{ textAlign: 'left' }}>
            <button
              onClick={() => setShowDetails(!showDetails)}
              style={{
                background: 'none',
                border: 'none',
                color: '#484F58',
                fontSize: 12,
                cursor: 'pointer',
                padding: '4px 0',
                fontFamily: "'Plus Jakarta Sans', system-ui, sans-serif",
                display: 'flex',
                alignItems: 'center',
                gap: 6,
                transition: 'color 0.15s',
              }}
              onMouseEnter={e => e.currentTarget.style.color = '#8B949E'}
              onMouseLeave={e => e.currentTarget.style.color = '#484F58'}
            >
              <svg
                width="12"
                height="12"
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                strokeWidth="2"
                strokeLinecap="round"
                strokeLinejoin="round"
                style={{
                  transform: showDetails ? 'rotate(90deg)' : 'rotate(0deg)',
                  transition: 'transform 0.2s',
                }}
              >
                <polyline points="9 18 15 12 9 6" />
              </svg>
              Technical details
            </button>
            {showDetails && (
              <div style={{
                marginTop: 8,
                padding: 16,
                borderRadius: 10,
                backgroundColor: '#0D1117',
                border: '1px solid #21262D',
                maxHeight: 200,
                overflow: 'auto',
              }}>
                <div style={{
                  fontFamily: "'JetBrains Mono', 'Fira Code', monospace",
                  fontSize: 11,
                  lineHeight: 1.5,
                  color: '#F85149',
                  wordBreak: 'break-word',
                  whiteSpace: 'pre-wrap',
                  marginBottom: stackText || componentStack ? 8 : 0,
                }}>
                  {errorText}
                </div>
                {stackText && (
                  <div style={{
                    fontFamily: "'JetBrains Mono', 'Fira Code', monospace",
                    fontSize: 10,
                    lineHeight: 1.4,
                    color: '#484F58',
                    wordBreak: 'break-word',
                    whiteSpace: 'pre-wrap',
                  }}>
                    {stackText}
                  </div>
                )}
                {componentStack && (
                  <div style={{
                    fontFamily: "'JetBrains Mono', 'Fira Code', monospace",
                    fontSize: 10,
                    lineHeight: 1.4,
                    color: '#484F58',
                    wordBreak: 'break-word',
                    whiteSpace: 'pre-wrap',
                    marginTop: 8,
                    borderTop: '1px solid #21262D',
                    paddingTop: 8,
                  }}>
                    Component stack:{componentStack}
                  </div>
                )}
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
}

export default ErrorBoundary;
