/**
 * Dynamically load a translation bundle for the given language code.
 * Returns a promise that resolves once the resource is registered with i18next.
 */
export function loadLanguage(lng) {
  if (lng === 'en') return Promise.resolve() // already bundled
  const loader = loaders[lng]
  if (!loader) return Promise.resolve()
  if (i18n.hasResourceBundle(lng, 'translation')) return Promise.resolve()
  return loader().then(mod => {
    i18n.addResourceBundle(lng, 'translation', mod.default || mod, true, true)
  })
}

i18n
  .use(LanguageDetector)
  .use(initReactI18next)
  .init({
    resources: {
      en: { translation: en },
    },
    fallbackLng: 'en',
    interpolation: {
      escapeValue: false,
    },
    detection: {
      order: ['localStorage', 'navigator'],
      caches: ['localStorage'],
      lookupLocalStorage: 'aura_language',
    },
  })

// After init, if the detected language is not English, load it immediately
const detected = i18n.language?.split('-')[0]
if (detected && detected !== 'en' && loaders[detected]) {
  loadLanguage(detected)
}

// Whenever the language changes, load the bundle if needed
i18n.on('languageChanged', (lng) => {
  const code = lng?.split('-')[0]
  if (code && code !== 'en') {
    loadLanguage(code)
  }
})

export default i18n
