import { createContext, useContext, useState, useEffect } from 'react';
import { getUser } from '@/utils/auth';

const LayoutContext = createContext(undefined);

export function LayoutProvider({ children }) {
  const user = getUser();

  const getInitialMode = () => {
    if (!user) return 'trader';

    const stored = localStorage.getItem('layout_mode');
    if (stored && user.subscription_tier === 'elite_997') return stored;

    // Active/Power -> Trader, Elite -> Operator
    return user.subscription_tier === 'elite_997' ? 'operator' : 'trader';
  };

  const [mode, setModeState] = useState(getInitialMode);
  const canToggle = user?.subscription_tier === 'elite_997' || user?.role === 'admin';

  const setMode = (newMode) => {
    if (!canToggle && newMode === 'operator') return;
    setModeState(newMode);
    localStorage.setItem('layout_mode', newMode);
    document.documentElement.setAttribute('data-mode', newMode);
  };

  const toggleMode = () => {
    if (!canToggle) return;
    setMode(mode === 'trader' ? 'operator' : 'trader');
  };

  useEffect(() => {
    document.documentElement.setAttribute('data-mode', mode);
  }, [mode]);

  return (
    <LayoutContext.Provider value={{ mode, setMode, toggleMode, canToggle }}>
      {children}
    </LayoutContext.Provider>
  );
}

export function useLayoutMode() {
  const context = useContext(LayoutContext);
  if (!context) return { mode: 'trader', setMode: () => {}, toggleMode: () => {}, canToggle: false };
  return context;
}

export default LayoutContext;
