import { useEffect, useRef, useCallback } from 'react';
import { api } from '../utils/api';
import useCelebration from './useCelebration';

/**
 * Global achievement listener — polls notifications for achievement_unlocked events
 * and triggers celebration overlay from any page.
 */
export function useGlobalAchievements() {
  const { celebrateAchievements, CelebrationOverlay } = useCelebration();
  const seenRef = useRef(new Set());
  const initRef = useRef(false);

  const checkNotifications = useCallback(async () => {
    try {
      const data = await api('/competition/notifications?unread_only=true&limit=10', { silent: true });
      if (!data?.notifications) return;

      const achievements = data.notifications.filter(
        n => n.type === 'achievement_unlocked' && !seenRef.current.has(n.id)
      );

      if (achievements.length > 0 && initRef.current) {
        // Mark as seen locally
        achievements.forEach(a => seenRef.current.add(a.id));

        // Build badge objects for celebration
        const badges = achievements.map(a => ({
          name: a.data?.name || a.title?.replace('Achievement: ', '').replace('!', '') || 'Badge',
          desc: a.body || '',
          tier: a.data?.tier || 'rare',
          badge_key: a.data?.badge_key || '',
          xp_awarded: a.data?.xp_awarded || 0,
        }));

        celebrateAchievements(badges);
      }

      // After first check, enable celebrations
      if (!initRef.current) {
        // Seed the seen set with current unread achievements
        data.notifications.forEach(n => {
          if (n.type === 'achievement_unlocked') seenRef.current.add(n.id);
        });
        initRef.current = true;
      }
    } catch {
      // Silent — don't break the app
    }
  }, [celebrateAchievements]);

  useEffect(() => {
    // Initial check
    checkNotifications();
    // Poll every 30 seconds
    const interval = setInterval(checkNotifications, 30000);

    // Also listen for programmatic triggers
    const handleCustom = (e) => {
      if (e.detail?.badges) {
        celebrateAchievements(e.detail.badges);
      }
    };
    window.addEventListener('aura:achievement-unlocked', handleCustom);

    return () => {
      clearInterval(interval);
      window.removeEventListener('aura:achievement-unlocked', handleCustom);
    };
  }, [checkNotifications, celebrateAchievements]);

  return { CelebrationOverlay };
}
