/**
 * AURA ALPHA — useIsNativeApp Hook
 * Detects if the app is running inside a Capacitor native shell (iOS/Android).
 * Uses synchronous check since Capacitor injects window.Capacitor before app loads.
 *
 * Usage:
 *   const isNative = useIsNativeApp();
 *   // isNative === true  → iOS/Android (Capacitor)
 *   // isNative === false → Web browser / desktop
 */

function checkNativePlatform() {
  try {
    return window.Capacitor?.isNativePlatform?.() || false;
  } catch {
    return false;
  }
}

// Evaluated once at module load — stable across renders
const IS_NATIVE = checkNativePlatform();

export default function useIsNativeApp() {
  return IS_NATIVE;
}

// Also export the raw boolean for non-hook contexts (e.g., route config)
export { IS_NATIVE };
