/* ═══════════════════════════════════════════════════════════════════════════
   AURA ALPHA — Page-Level Error Boundary
   Catches render errors per-page without crashing the entire app shell.
   Shows a polished "Something went wrong" UI with retry button.
   Logs error to console and reports to Sentry if available.
   ═══════════════════════════════════════════════════════════════════════════ */
import { Component, useState } from 'react';

export default class PageErrorBoundary extends Component {
  state = { error: null, errorInfo: null, sentryReported: false };

  static getDerivedStateFromError(error) {
    return { error };
  }

  componentDidCatch(error, errorInfo) {
    this.setState({ errorInfo });

    // Always log to console
    console.error('[PageErrorBoundary]', error, errorInfo);

    // Report to Sentry/GlitchTip if available
    try {
      import('@sentry/react').then(Sentry => {
        if (Sentry.isInitialized?.() || Sentry.getCurrentHub?.().getClient?.()) {
          Sentry.captureException(error, {
            extra: {
              componentStack: errorInfo?.componentStack,
              page: window.location.pathname,
            },
          });
          this.setState({ sentryReported: true });
        }
      }).catch(() => {});
    } catch (_) { /* Sentry not available */ }
  }

  handleRetry = () => {
    this.setState({ error: null, errorInfo: null, sentryReported: false });
    this.props.onReset?.();
  };

  render() {
    if (this.state.error) {
      return (
        <PageErrorFallback
          error={this.state.error}
          errorInfo={this.state.errorInfo}
          sentryReported={this.state.sentryReported}
          onRetry={this.handleRetry}
        />
      );
    }
    return this.props.children;
  }
}

function PageErrorFallback({ error, errorInfo, sentryReported, onRetry }) {
  const [showDetails, setShowDetails] = useState(false);
  const errorText = error?.message || error?.toString() || 'Unknown error';
  const componentStack = errorInfo?.componentStack || '';

  return (
    <div style={{
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      minHeight: 360,
      padding: 32,
      backgroundColor: '#0D1117',
      fontFamily: "'Plus Jakarta Sans', system-ui, sans-serif",
    }}>
      <div style={{
        textAlign: 'center',
        maxWidth: 460,
        width: '100%',
        padding: 36,
        borderRadius: 16,
        backgroundColor: '#161B22',
        border: '1px solid #30363D',
        boxShadow: '0 8px 32px rgba(0, 0, 0, 0.35)',
      }}>
        {/* Error icon */}
        <div style={{
          width: 52,
          height: 52,
          borderRadius: '50%',
          background: 'linear-gradient(135deg, rgba(248,81,73,0.12), rgba(210,153,34,0.12))',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          margin: '0 auto 20px',
        }}>
          <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="#F85149" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <circle cx="12" cy="12" r="10" />
            <line x1="12" y1="8" x2="12" y2="12" />
            <line x1="12" y1="16" x2="12.01" y2="16" />
          </svg>
        </div>

        <h3 style={{
          color: '#E6EDF3',
          fontSize: 18,
          fontWeight: 700,
          margin: '0 0 8px 0',
          letterSpacing: '-0.01em',
        }}>
          Something went wrong
        </h3>

        <p style={{
          color: '#8B949E',
          fontSize: 13,
          margin: '0 0 6px 0',
          lineHeight: 1.6,
        }}>
          This page encountered an error. The rest of the app is still working.
        </p>

        {sentryReported && (
          <p style={{
            color: '#3FB950',
            fontSize: 11,
            margin: '0 0 20px 0',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            gap: 5,
          }}>
            <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="#3FB950" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
              <polyline points="20 6 9 17 4 12" />
            </svg>
            Error automatically reported
          </p>
        )}

        {!sentryReported && <div style={{ height: 14 }} />}

        {/* Actions */}
        <div style={{ display: 'flex', gap: 10, justifyContent: 'center', flexWrap: 'wrap', marginBottom: 18 }}>
          <button
            onClick={onRetry}
            style={{
              padding: '10px 24px',
              borderRadius: 10,
              border: 'none',
              background: 'linear-gradient(135deg, #60A5FA, #A78BFA)',
              color: '#ffffff',
              fontSize: 13,
              fontWeight: 600,
              cursor: 'pointer',
              fontFamily: "'Plus Jakarta Sans', system-ui, sans-serif",
              boxShadow: '0 4px 16px rgba(96, 165, 250, 0.25)',
              transition: 'opacity 200ms',
            }}
            onMouseEnter={e => e.currentTarget.style.opacity = '0.85'}
            onMouseLeave={e => e.currentTarget.style.opacity = '1'}
          >
            Retry
          </button>
          <button
            onClick={() => window.location.reload()}
            style={{
              padding: '10px 24px',
              borderRadius: 10,
              border: '1px solid #30363D',
              background: 'transparent',
              color: '#8B949E',
              fontSize: 13,
              fontWeight: 600,
              cursor: 'pointer',
              fontFamily: "'Plus Jakarta Sans', system-ui, sans-serif",
              transition: 'border-color 200ms, color 200ms',
            }}
            onMouseEnter={e => { e.currentTarget.style.borderColor = '#8B949E'; e.currentTarget.style.color = '#E6EDF3'; }}
            onMouseLeave={e => { e.currentTarget.style.borderColor = '#30363D'; e.currentTarget.style.color = '#8B949E'; }}
          >
            Reload Page
          </button>
          <button
            onClick={() => { window.location.href = '/home'; }}
            style={{
              padding: '10px 24px',
              borderRadius: 10,
              border: '1px solid #30363D',
              background: 'transparent',
              color: '#8B949E',
              fontSize: 13,
              fontWeight: 600,
              cursor: 'pointer',
              fontFamily: "'Plus Jakarta Sans', system-ui, sans-serif",
              transition: 'border-color 200ms, color 200ms',
            }}
            onMouseEnter={e => { e.currentTarget.style.borderColor = '#8B949E'; e.currentTarget.style.color = '#E6EDF3'; }}
            onMouseLeave={e => { e.currentTarget.style.borderColor = '#30363D'; e.currentTarget.style.color = '#8B949E'; }}
          >
            Go Home
          </button>
        </div>

        {/* Collapsible details */}
        <div style={{ textAlign: 'left' }}>
          <button
            onClick={() => setShowDetails(!showDetails)}
            style={{
              background: 'none',
              border: 'none',
              color: '#484F58',
              fontSize: 11,
              cursor: 'pointer',
              padding: '4px 0',
              fontFamily: "'Plus Jakarta Sans', system-ui, sans-serif",
              display: 'flex',
              alignItems: 'center',
              gap: 6,
              transition: 'color 200ms',
            }}
            onMouseEnter={e => e.currentTarget.style.color = '#8B949E'}
            onMouseLeave={e => e.currentTarget.style.color = '#484F58'}
          >
            <svg
              width="11" height="11" viewBox="0 0 24 24"
              fill="none" stroke="currentColor" strokeWidth="2"
              strokeLinecap="round" strokeLinejoin="round"
              style={{
                transform: showDetails ? 'rotate(90deg)' : 'rotate(0deg)',
                transition: 'transform 200ms',
              }}
            >
              <polyline points="9 18 15 12 9 6" />
            </svg>
            Technical details
          </button>
          {showDetails && (
            <div style={{
              marginTop: 6,
              padding: 14,
              borderRadius: 10,
              backgroundColor: '#0D1117',
              border: '1px solid #21262D',
              maxHeight: 180,
              overflow: 'auto',
            }}>
              <div style={{
                fontFamily: "'JetBrains Mono', 'Fira Code', monospace",
                fontSize: 10,
                lineHeight: 1.5,
                color: '#F85149',
                wordBreak: 'break-word',
                whiteSpace: 'pre-wrap',
                marginBottom: componentStack ? 8 : 0,
              }}>
                {errorText}
              </div>
              {componentStack && (
                <div style={{
                  fontFamily: "'JetBrains Mono', 'Fira Code', monospace",
                  fontSize: 9,
                  lineHeight: 1.4,
                  color: '#484F58',
                  wordBreak: 'break-word',
                  whiteSpace: 'pre-wrap',
                  borderTop: '1px solid #21262D',
                  paddingTop: 6,
                  marginTop: 6,
                }}>
                  Component stack:{componentStack}
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
