/* ═══════════════════════════════════════════════════════════════════════════
   AURA ALPHA — Reconnecting Banner
   Subtle top-of-page banner that shows when the API connection is lost.
   Green pulse when reconnected, amber when degraded, red when disconnected.
   ═══════════════════════════════════════════════════════════════════════════ */
import { useState, useEffect } from 'react';
import useConnectionHealth from '../hooks/useConnectionHealth';

export default function ReconnectingBanner() {
  const { healthy, reconnecting } = useConnectionHealth();
  const [showRecovered, setShowRecovered] = useState(false);
  const [wasUnhealthy, setWasUnhealthy] = useState(false);

  // Track recovery: show brief "Connected" message after reconnection
  useEffect(() => {
    if (!healthy) {
      setWasUnhealthy(true);
    } else if (wasUnhealthy) {
      setShowRecovered(true);
      setWasUnhealthy(false);
      const timer = setTimeout(() => setShowRecovered(false), 3000);
      return () => clearTimeout(timer);
    }
  }, [healthy, wasUnhealthy]);

  // Don't render anything if connection is healthy and no recent recovery
  if (healthy && !showRecovered) return null;

  const isRecovered = healthy && showRecovered;

  return (
    <div
      role="alert"
      aria-live="assertive"
      style={{
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        gap: 10,
        padding: '8px 16px',
        fontSize: 12,
        fontWeight: 600,
        fontFamily: "'Plus Jakarta Sans', system-ui, sans-serif",
        color: isRecovered ? '#3FB950' : reconnecting ? '#D29922' : '#F85149',
        background: isRecovered
          ? 'rgba(63, 185, 80, 0.08)'
          : reconnecting
            ? 'rgba(210, 153, 34, 0.08)'
            : 'rgba(248, 81, 73, 0.08)',
        borderBottom: `1px solid ${
          isRecovered ? 'rgba(63, 185, 80, 0.2)' : reconnecting ? 'rgba(210, 153, 34, 0.2)' : 'rgba(248, 81, 73, 0.2)'
        }`,
        transition: 'all 300ms ease',
        zIndex: 9999,
      }}
    >
      {/* Animated dot */}
      <span
        style={{
          width: 8,
          height: 8,
          borderRadius: '50%',
          backgroundColor: isRecovered ? '#3FB950' : reconnecting ? '#D29922' : '#F85149',
          animation: isRecovered ? 'none' : 'reconnectPulse 1.5s ease-in-out infinite',
          flexShrink: 0,
        }}
      />

      {isRecovered
        ? 'Connection restored'
        : reconnecting
          ? 'Reconnecting to server...'
          : 'Unable to reach the server'}

      {/* Spinner for reconnecting state */}
      {reconnecting && (
        <svg
          width="14"
          height="14"
          viewBox="0 0 24 24"
          fill="none"
          stroke="#D29922"
          strokeWidth="2.5"
          strokeLinecap="round"
          style={{ animation: 'reconnectSpin 1s linear infinite' }}
        >
          <path d="M21 12a9 9 0 11-6.219-8.56" />
        </svg>
      )}

      <style>{`
        @keyframes reconnectPulse {
          0%, 100% { opacity: 1; }
          50% { opacity: 0.3; }
        }
        @keyframes reconnectSpin {
          from { transform: rotate(0deg); }
          to { transform: rotate(360deg); }
        }
      `}</style>
    </div>
  );
}
