import { useEffect, useRef, useState, useCallback } from "react";

const POLL_MS = 60_000;

export function useVersionCheck() {
  const [remoteHash, setRemoteHash] = useState(null);
  const [remoteVersion, setRemoteVersion] = useState(null);
  const [dismissed, setDismissed] = useState(false);
  const dismissedHash = useRef(null);
  const alive = useRef(true);

  useEffect(() => {
    alive.current = true;
    return () => { alive.current = false; };
  }, []);

  useEffect(() => {
    const check = async () => {
      try {
        const res = await fetch(`/version.json?_=${Date.now()}`);
        if (!res.ok || !alive.current) return;
        const json = await res.json();
        if (!alive.current) return;
        setRemoteHash(json.hash);
        setRemoteVersion(json.version);
        // If hash changed since last dismiss, un-dismiss
        if (dismissedHash.current && dismissedHash.current !== json.hash) {
          setDismissed(false);
          dismissedHash.current = null;
        }
      } catch { /* silent — version.json may not exist in dev */ }
    };

    check();
    const t = setInterval(check, POLL_MS);
    return () => clearInterval(t);
  }, []);

  const currentHash = typeof __BUILD_HASH__ !== "undefined" ? __BUILD_HASH__ : "dev";
  const currentVersion = typeof __APP_VERSION__ !== "undefined" ? __APP_VERSION__ : "dev";

  const updateAvailable = !!(remoteHash && remoteHash !== currentHash && !dismissed);

  const dismiss = useCallback(() => {
    setDismissed(true);
    dismissedHash.current = remoteHash;
  }, [remoteHash]);

  const refresh = useCallback(() => {
    window.location.reload();
  }, []);

  return {
    updateAvailable,
    currentVersion,
    currentHash,
    remoteVersion,
    remoteHash,
    dismiss,
    refresh,
  };
}
