import { useState, useEffect } from 'react';
import T from '../tokens';

// ── Consent storage key ────────────────────────────────────────────────
const CONSENT_KEY = 'aura_cookie_consent';

/**
 * Check whether the user has granted analytics consent.
 *
 * Use this to gate third-party analytics scripts (Google Analytics, etc.).
 * First-party analytics (our own /api/ml/events pipeline) are classified
 * as "Essential / Functional" and are NOT gated by this check.
 *
 * Usage:
 *   import { hasAnalyticsConsent } from '@/components/CookieConsent';
 *   if (hasAnalyticsConsent()) { loadGoogleAnalytics(); }
 */
export function hasAnalyticsConsent() {
  try {
    return localStorage.getItem(CONSENT_KEY) === 'all';
  } catch {
    return false;
  }
}

/**
 * Returns the raw consent value: 'all' | 'essential' | null
 */
export function getConsentLevel() {
  try {
    return localStorage.getItem(CONSENT_KEY);
  } catch {
    return null;
  }
}

// ── Cookie categories (displayed in the banner) ───────────────────────
const CATEGORIES = [
  {
    name: 'Essential',
    always: true,
    description: 'Authentication, preferences, CSRF protection',
  },
  {
    name: 'Functional',
    always: true,
    description: 'Chat, notifications, first-party usage tracking',
  },
  {
    name: 'Analytics',
    always: false,
    description: 'Third-party usage patterns & page views (e.g. Google Analytics)',
  },
];

export default function CookieConsent() {
  const [show, setShow] = useState(false);
  const [expanded, setExpanded] = useState(false);

  useEffect(() => {
    try {
      const consent = localStorage.getItem(CONSENT_KEY);
      if (!consent) setShow(true);
    } catch { setShow(true); }
  }, []);

  const accept = (level) => {
    try { localStorage.setItem(CONSENT_KEY, level); } catch {}
    setShow(false);

    // Dispatch a custom event so other parts of the app can react to consent changes
    window.dispatchEvent(new CustomEvent('aura_consent_change', { detail: { level } }));
  };

  if (!show) return null;

  return (
    <div style={{
      position: 'fixed', bottom: 0, left: 0, right: 0, zIndex: 9999,
      background: T.surface, borderTop: `1px solid ${T.border}`,
      padding: '16px 24px',
      backdropFilter: 'blur(12px)',
      boxShadow: '0 -8px 30px rgba(0,0,0,0.4)',
    }}>
      <div style={{
        maxWidth: 960, margin: '0 auto',
        display: 'flex', flexDirection: 'column', gap: 12,
      }}>
        {/* Main row: text + buttons */}
        <div style={{
          display: 'flex', alignItems: 'center', justifyContent: 'space-between',
          gap: 16, flexWrap: 'wrap',
        }}>
          <p style={{ fontSize: 13, color: T.textSecondary, margin: 0, flex: 1, minWidth: 260, lineHeight: 1.5 }}>
            We use cookies for authentication and to improve your experience.{' '}
            <button
              onClick={() => setExpanded(v => !v)}
              style={{
                background: 'none', border: 'none', color: T.blue,
                cursor: 'pointer', fontSize: 13, padding: 0, textDecoration: 'underline',
                fontFamily: 'inherit',
              }}
            >
              {expanded ? 'Hide details' : 'Show details'}
            </button>
            {' '}&middot;{' '}
            <a href="/cookies" style={{ color: T.blue, textDecoration: 'none' }}>Cookie Policy</a>
            {' '}&middot;{' '}
            <a href="/privacy" style={{ color: T.blue, textDecoration: 'none' }}>Privacy Policy</a>
          </p>
          <div style={{ display: 'flex', gap: 8 }}>
            <button
              onClick={() => accept('essential')}
              style={{
                padding: '8px 16px', borderRadius: 10,
                background: 'transparent', border: `1px solid ${T.border}`,
                color: T.textPrimary, fontSize: 13, fontWeight: 600, cursor: 'pointer',
              }}
            >
              Essential Only
            </button>
            <button
              onClick={() => accept('all')}
              style={{
                padding: '8px 16px', borderRadius: 10,
                background: T.blue, border: 'none',
                color: '#fff', fontSize: 13, fontWeight: 600, cursor: 'pointer',
              }}
            >
              Accept All
            </button>
          </div>
        </div>

        {/* Expandable category details */}
        {expanded && (
          <div style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))',
            gap: 10,
            paddingTop: 4,
            borderTop: `1px solid ${T.border}`,
          }}>
            {CATEGORIES.map(cat => (
              <div key={cat.name} style={{
                padding: '8px 12px',
                borderRadius: 8,
                background: 'rgba(255,255,255,0.03)',
                border: `1px solid ${T.border}`,
              }}>
                <div style={{
                  display: 'flex', alignItems: 'center', justifyContent: 'space-between',
                  marginBottom: 4,
                }}>
                  <span style={{ fontSize: 12, fontWeight: 600, color: T.textPrimary }}>
                    {cat.name}
                  </span>
                  <span style={{
                    fontSize: 10, fontWeight: 600, borderRadius: 4, padding: '2px 6px',
                    background: cat.always ? 'rgba(63,185,80,0.15)' : 'rgba(210,153,34,0.15)',
                    color: cat.always ? T.green : T.amber,
                  }}>
                    {cat.always ? 'Always on' : 'Optional'}
                  </span>
                </div>
                <p style={{ fontSize: 11, color: T.textSecondary, margin: 0, lineHeight: 1.4 }}>
                  {cat.description}
                </p>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
