/* ═══════════════════════════════════════════════════════════════════════════
   AURA ALPHA — Connection Health Hook
   Tracks API connectivity state via window events dispatched by api.js.
   Returns: { healthy, degraded, reconnecting }
   - healthy:      true when all API calls succeed
   - degraded:     true when some endpoints are failing
   - reconnecting: true when connection was lost and retries are happening
   ═══════════════════════════════════════════════════════════════════════════ */
import { useState, useEffect, useCallback, useRef } from 'react';
import { isApiHealthy } from '../utils/api';
import { getApiBase } from '../utils/platform';

export default function useConnectionHealth() {
  const [healthy, setHealthy] = useState(() => isApiHealthy());
  const [reconnecting, setReconnecting] = useState(false);
  const reconnectTimer = useRef(null);
  const wasUnhealthy = useRef(false);

  // Listen for connection change events from api.js
  useEffect(() => {
    const handler = (e) => {
      const { healthy: isHealthy } = e.detail;
      if (isHealthy) {
        setHealthy(true);
        setReconnecting(false);
        wasUnhealthy.current = false;
        if (reconnectTimer.current) {
          clearInterval(reconnectTimer.current);
          reconnectTimer.current = null;
        }
      } else {
        setHealthy(false);
        wasUnhealthy.current = true;
        // Start reconnection polling if not already running
        if (!reconnectTimer.current) {
          setReconnecting(true);
          reconnectTimer.current = setInterval(async () => {
            try {
              const r = await fetch(`${getApiBase()}/health`, {
                signal: AbortSignal.timeout?.(5000),
              });
              if (r.ok) {
                setHealthy(true);
                setReconnecting(false);
                wasUnhealthy.current = false;
                if (reconnectTimer.current) {
                  clearInterval(reconnectTimer.current);
                  reconnectTimer.current = null;
                }
              }
            } catch {
              // Still disconnected, keep polling
            }
          }, 10000); // Check every 10 seconds
        }
      }
    };

    window.addEventListener('aura:connection-change', handler);
    return () => {
      window.removeEventListener('aura:connection-change', handler);
      if (reconnectTimer.current) {
        clearInterval(reconnectTimer.current);
        reconnectTimer.current = null;
      }
    };
  }, []);

  return {
    healthy,
    degraded: !healthy && !reconnecting,
    reconnecting,
  };
}
