/**
 * Prefetch Manager -- loads all critical API data on app startup.
 *
 * On app open (when Shell mounts), fires parallel requests to every API
 * endpoint the user will need. Results are stored in a global cache that
 * hooks read from instantly (no loading spinner).
 *
 * Cache is refreshed in the background every 30 seconds.
 *
 * Uses the existing api() helper which already handles:
 *  - Auth headers (Bearer token from localStorage)
 *  - Token refresh on 401
 *  - Retry with exponential backoff
 *  - In-flight request deduplication
 */

import { api } from './api';

const PREFETCH_ENDPOINTS = [
  // Core dashboard data
  { key: 'telemetry', url: '/telemetry/latest', ttl: 5000 },
  { key: 'bots', url: '/bots', ttl: 10000 },
  { key: 'health', url: '/health', ttl: 5000 },
  { key: 'systemHealth', url: '/system/health', ttl: 10000 },

  // Positions & orders
  { key: 'positions', url: '/positions', ttl: 5000 },
  { key: 'orders', url: '/orders/blotter', ttl: 10000 },

  // Strategies
  { key: 'strategies', url: '/strategies', ttl: 30000 },
  { key: 'strategiesNormalized', url: '/strategies/normalized', ttl: 30000 },

  // Risk
  { key: 'riskExposure', url: '/risk/exposure', ttl: 10000 },

  // P&L
  { key: 'pnl', url: '/pnl/snapshot', ttl: 5000 },
  { key: 'equityHistory', url: '/telemetry/equity-history', ttl: 30000 },

  // Watchlists & alerts
  { key: 'watchlists', url: '/watchlists', ttl: 30000 },
  { key: 'alerts', url: '/alerts', ttl: 15000 },

  // AI digest
  { key: 'aiDigest', url: '/ai/digest', ttl: 60000 },

  // Scanner signals
  { key: 'scannerSignals', url: '/scanners/signals/live', ttl: 10000 },

  // Account / broker connections
  { key: 'brokerConnections', url: '/brokers', ttl: 60000 },
];

class PrefetchManager {
  constructor() {
    this.cache = new Map();
    this.loading = new Set();
    this.listeners = new Map(); // key -> Set<callback>
    this.refreshInterval = null;
    this.initialized = false;
  }

  async prefetchAll() {
    const token = localStorage.getItem('aura_token');
    if (!token) return;

    const start = performance.now();

    // Fire ALL requests in parallel using api() which handles auth
    const promises = PREFETCH_ENDPOINTS.map(async (ep) => {
      try {
        this.loading.add(ep.key);
        const data = await api(ep.url, { silent: true });
        if (data) {
          this.cache.set(ep.key, {
            data,
            timestamp: Date.now(),
            ttl: ep.ttl,
          });
          this._notify(ep.key, data);
        }
      } catch (e) {
        // Silent fail -- page will fetch on demand if prefetch fails
      } finally {
        this.loading.delete(ep.key);
      }
    });

    await Promise.allSettled(promises);

    const elapsed = performance.now() - start;
    if (import.meta.env.DEV) console.log(`[Prefetch] ${PREFETCH_ENDPOINTS.length} endpoints loaded in ${elapsed.toFixed(0)}ms`);
    this.initialized = true;

    // Start background refresh
    this._startRefresh();
  }

  /** Read from cache. Returns null if missing or expired. */
  get(key) {
    const entry = this.cache.get(key);
    if (!entry) return null;
    if (Date.now() - entry.timestamp > entry.ttl) return null; // expired
    return entry.data;
  }

  /** Subscribe to cache updates for a key. Returns unsubscribe function. */
  subscribe(key, callback) {
    if (!this.listeners.has(key)) this.listeners.set(key, new Set());
    this.listeners.get(key).add(callback);
    // Immediately call with cached data if available
    const cached = this.get(key);
    if (cached) callback(cached);
    return () => this.listeners.get(key)?.delete(callback);
  }

  _notify(key, data) {
    this.listeners.get(key)?.forEach(cb => {
      try { cb(data); } catch (e) { /* subscriber error, ignore */ }
    });
  }

  _startRefresh() {
    if (this.refreshInterval) return;
    this.refreshInterval = setInterval(() => {
      // Skip refresh when tab is hidden to save bandwidth
      if (document.hidden) return;
      this.prefetchAll();
    }, 60000); // refresh every 60s — was 30s, most TTLs are 10-30s anyway

    // Resume and refresh immediately when tab becomes visible
    this._onVisibility = () => {
      if (!document.hidden) this.prefetchAll();
    };
    document.addEventListener('visibilitychange', this._onVisibility);
  }

  destroy() {
    if (this.refreshInterval) clearInterval(this.refreshInterval);
    if (this._onVisibility) document.removeEventListener('visibilitychange', this._onVisibility);
    this.refreshInterval = null;
    this.cache.clear();
    this.listeners.clear();
    this.initialized = false;
  }
}

export const prefetch = new PrefetchManager();
export default prefetch;
