import { isNative } from './platform';
import { hydrateFromNative } from './storage';

/** Race a promise against a timeout — resolves undefined on timeout */
function withTimeout(promise, ms = 3000) {
  return Promise.race([
    promise,
    new Promise(resolve => setTimeout(resolve, ms)),
  ]);
}

/**
 * Initialize native platform features.
 * Runs in background after React mounts — non-blocking.
 * Each plugin call has a 3s timeout to prevent hangs.
 */
export async function initNative() {
  if (!isNative()) return;

  // 1. Hydrate localStorage from native Preferences (tokens, user)
  // NOTE: main.jsx already hydrates BEFORE React mounts to avoid auth race.
  // This is a safe no-op re-run (just overwrites same values).
  try { await withTimeout(hydrateFromNative()); } catch (e) { console.warn('hydrateFromNative failed:', e); }

  // 2. Platform class already set synchronously in main.jsx

  // 3. Status bar styling
  try {
    const { StatusBar, Style } = await import('@capacitor/status-bar');
    await withTimeout(StatusBar.setStyle({ style: Style.Dark }));
  } catch { /* optional plugin */ }

  // 4. Keyboard listeners — shift content up when keyboard opens
  try {
    const { Keyboard } = await import('@capacitor/keyboard');
    Keyboard.addListener('keyboardWillShow', (info) => {
      document.body.style.setProperty('--keyboard-height', `${info.keyboardHeight}px`);
      document.body.classList.add('keyboard-visible');
    });
    Keyboard.addListener('keyboardWillHide', () => {
      document.body.style.setProperty('--keyboard-height', '0px');
      document.body.classList.remove('keyboard-visible');
    });
  } catch { /* optional plugin */ }

  // 5. Back button — navigate browser history
  try {
    const { App } = await import('@capacitor/app');
    App.addListener('backButton', ({ canGoBack }) => {
      if (canGoBack) {
        window.history.back();
      }
    });
  } catch { /* optional plugin */ }

  // 6. Hide splash screen
  try {
    const { SplashScreen } = await import('@capacitor/splash-screen');
    await withTimeout(SplashScreen.hide({ fadeOutDuration: 300 }));
  } catch { /* optional plugin */ }

  // 7. Initialize In-App Purchases (StoreKit 2)
  try {
    const { default: iapService } = await import('@/services/iapService');
    await withTimeout(iapService.initialize(), 5000);
  } catch (e) { console.warn('IAP init failed (non-fatal):', e); }
}
