/**
 * useOnlineStatus -- Detects browser online/offline state.
 *
 * Uses `navigator.onLine` for initial value, then listens for the
 * `online` and `offline` window events.
 *
 * Returns:
 *   { isOnline, wasOffline }
 *
 *   - isOnline:    true when navigator reports connectivity
 *   - wasOffline:  true briefly after reconnection (for "Connected" flash)
 *
 * The "wasOffline" flag stays true for 3 seconds after going back online,
 * giving the UI time to show a "Connected" confirmation before hiding.
 */
import { useState, useEffect, useRef, useCallback } from 'react';

const RECONNECT_FLASH_MS = 3000; // Show "Connected" for 3s after reconnection

export default function useOnlineStatus() {
  const [isOnline, setIsOnline] = useState(() => {
    try { return navigator.onLine; } catch { return true; }
  });
  const [wasOffline, setWasOffline] = useState(false);
  const flashTimer = useRef(null);
  const hadDisconnect = useRef(false);

  const handleOnline = useCallback(() => {
    setIsOnline(true);
    if (hadDisconnect.current) {
      setWasOffline(true);
      // Clear any existing timer
      if (flashTimer.current) clearTimeout(flashTimer.current);
      flashTimer.current = setTimeout(() => {
        setWasOffline(false);
        hadDisconnect.current = false;
      }, RECONNECT_FLASH_MS);
    }
  }, []);

  const handleOffline = useCallback(() => {
    setIsOnline(false);
    hadDisconnect.current = true;
    setWasOffline(false);
    if (flashTimer.current) {
      clearTimeout(flashTimer.current);
      flashTimer.current = null;
    }
  }, []);

  useEffect(() => {
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
      if (flashTimer.current) clearTimeout(flashTimer.current);
    };
  }, [handleOnline, handleOffline]);

  return { isOnline, wasOffline };
}
