import { useState, useEffect, useCallback } from 'react';
import * as Popover from '@radix-ui/react-popover';
import { api, apiPost } from '../utils/api';
import { timeAgo } from '../utils/formatters';
import useUserBots from '../hooks/useUserBots';

const C = {
  bg: '#0B0F14',
  surface: '#0F1620',
  surface2: '#111A24',
  border: '#1F2A37',
  textPrimary: '#E5E7DB',
  textSecondary: '#90A3AF',
  green: '#22C55E',
  red: '#EF4444',
  blue: '#60A5FA',
  amber: '#F59E0B',
};
const mono = "'JetBrains Mono', monospace";
const body = "'Plus Jakarta Sans', sans-serif";

function statusColor(status) {
  if (!status) return C.textSecondary;
  const s = status.toLowerCase();
  if (['connected', 'active', 'healthy', 'online', 'running', 'ok'].includes(s)) return C.green;
  if (['degraded', 'stale', 'warning', 'reconnecting'].includes(s)) return C.amber;
  if (['disconnected', 'down', 'error', 'offline', 'stopped'].includes(s)) return C.red;
  return C.textSecondary;
}

function formatUptime(seconds) {
  if (!seconds && seconds !== 0) return '--';
  const h = Math.floor(seconds / 3600);
  const m = Math.floor((seconds % 3600) / 60);
  if (h > 24) return `${Math.floor(h / 24)}d ${h % 24}h`;
  if (h > 0) return `${h}h ${m}m`;
  return `${m}m`;
}

function formatTime(ts) {
  if (!ts) return '--';
  try {
    const ms = typeof ts === 'number' && ts < 1e12 ? ts * 1000 : ts;
    return new Date(ms).toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', second: '2-digit' });
  } catch { return '--'; }
}

/**
 * GatewayPopover — condensed gateway status in a Radix Popover.
 * Triggered from status pills in Shell.jsx top bar.
 */
export default function GatewayPopover({ children }) {
  const { bots: userBots } = useUserBots();
  const BOTS = userBots.map(b => ({ name: b.name, clientId: b.client_id || b.clientId, accent: b.color || C.blue }));
  const [health, setHealth] = useState(null);
  const [reconnecting, setReconnecting] = useState(false);
  const [open, setOpen] = useState(false);

  const fetchHealth = useCallback(async () => {
    try {
      const data = await api('/system/health');
      if (data) setHealth(data);
    } catch {}
  }, []);

  useEffect(() => {
    if (!open) return;
    fetchHealth();
    const iv = setInterval(fetchHealth, 30000);  // 30s — was 10s
    return () => clearInterval(iv);
  }, [open, fetchHealth]);

  const handleReconnect = async () => {
    setReconnecting(true);
    await apiPost('/system/reconnect', { service: 'ibkr_gateway' }).catch(() => {});
    setTimeout(() => { setReconnecting(false); fetchHealth(); }, 3000);
  };

  const gateway = health?.gateway || health?.ibkr || {};
  const gwConnected = gateway.connected ?? false;
  const gwStatus = gateway.status || (gwConnected ? 'connected' : 'disconnected');
  const gwUptime = gateway.uptime || gateway.uptime_seconds || null;
  const gwColor = statusColor(gwStatus);

  const rawBots = health?.bots || health?.telemetry || [];
  const botStatuses = Array.isArray(rawBots)
    ? rawBots
    : Object.entries(rawBots)
        .filter(([, v]) => typeof v === 'object' && v !== null && (v.bot || v.status || v.last_heartbeat))
        .map(([k, v]) => ({
          name: k.toUpperCase(),
          status: v.status || 'OK',
          lastHeartbeat: v.last_heartbeat,
          tradesToday: (v.payload?.trades || []).length,
        }));

  return (
    <Popover.Root open={open} onOpenChange={setOpen}>
      <Popover.Trigger asChild>
        {children}
      </Popover.Trigger>
      <Popover.Portal>
        <Popover.Content
          sideOffset={8}
          align="end"
          style={{
            width: 360, background: C.surface, border: `1px solid ${C.border}`,
            borderRadius: 14, boxShadow: '0 16px 48px rgba(0,0,0,0.5)',
            zIndex: 1000, overflow: 'hidden',
          }}
        >
          {/* Header */}
          <div style={{
            padding: '14px 16px', borderBottom: `1px solid ${C.border}`,
            display: 'flex', alignItems: 'center', gap: 12,
          }}>
            <div style={{
              width: 32, height: 32, borderRadius: '50%', background: `${gwColor}22`,
              display: 'flex', alignItems: 'center', justifyContent: 'center',
            }}>
              <div style={{
                width: 14, height: 14, borderRadius: '50%', background: gwColor,
                boxShadow: `0 0 10px ${gwColor}66`,
              }} />
            </div>
            <div style={{ flex: 1 }}>
              <div style={{ fontSize: 14, fontWeight: 700, color: gwColor, fontFamily: mono, textTransform: 'uppercase' }}>
                {gwStatus}
              </div>
              <div style={{ fontSize: 11, color: C.textSecondary }}>IB Gateway</div>
            </div>
            <button
              onClick={handleReconnect}
              disabled={reconnecting}
              style={{
                fontFamily: mono, fontSize: 11, fontWeight: 600, padding: '6px 14px',
                borderRadius: 6, border: `1px solid ${reconnecting ? C.border : C.amber}`,
                background: reconnecting ? C.surface2 : `${C.amber}20`,
                color: reconnecting ? C.textSecondary : C.amber,
                cursor: reconnecting ? 'not-allowed' : 'pointer',
              }}
            >
              {reconnecting ? '...' : 'Reconnect'}
            </button>
          </div>

          {/* Stats */}
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: 0, borderBottom: `1px solid ${C.border}` }}>
            {[
              { label: 'Host', value: gateway.host || '127.0.0.1' },
              { label: 'Port', value: gateway.port || 4001, color: C.blue },
              { label: 'Uptime', value: formatUptime(gwUptime), color: C.green },
            ].map(s => (
              <div key={s.label} style={{ padding: '10px 16px', borderRight: `1px solid ${C.border}` }}>
                <div style={{ fontSize: 10, color: C.textSecondary, textTransform: 'uppercase', marginBottom: 4, fontFamily: body }}>{s.label}</div>
                <div style={{ fontFamily: mono, fontSize: 13, fontWeight: 600, color: s.color || C.textPrimary }}>{s.value}</div>
              </div>
            ))}
          </div>

          {/* Bot connections */}
          <div style={{ padding: '8px 0' }}>
            <div style={{ padding: '4px 16px 8px', fontSize: 10, color: C.textSecondary, textTransform: 'uppercase', fontFamily: body, fontWeight: 600 }}>
              Bot Connections
            </div>
            {BOTS.length === 0 && (
              <div style={{ padding: '8px 16px', fontSize: 12, color: C.textSecondary, fontFamily: body }}>
                No bots configured
              </div>
            )}
            {BOTS.map(bot => {
              const live = botStatuses.find(b => (b.name || '').toUpperCase() === bot.name) || {};
              const bStatus = live.status || live.heartbeatStatus || 'unknown';
              const lastHb = live.lastHeartbeat || live.last_heartbeat || null;
              const trades = live.tradesToday || live.trades_today || 0;
              const bColor = statusColor(bStatus);
              return (
                <div key={bot.name} style={{
                  display: 'flex', alignItems: 'center', padding: '6px 16px', gap: 12,
                }}>
                  <span style={{
                    width: 8, height: 8, borderRadius: '50%', background: bColor,
                    boxShadow: `0 0 6px ${bColor}`, flexShrink: 0,
                  }} />
                  <span style={{ fontFamily: mono, fontSize: 13, fontWeight: 700, color: bot.accent, minWidth: 50 }}>{bot.name}</span>
                  <span style={{ fontFamily: mono, fontSize: 11, color: C.textSecondary, flex: 1 }}>
                    {lastHb ? formatTime(lastHb) : '--'}
                  </span>
                  <span style={{ fontFamily: mono, fontSize: 11, color: C.blue }}>{trades}t</span>
                </div>
              );
            })}
          </div>

          <Popover.Arrow style={{ fill: C.surface }} />
        </Popover.Content>
      </Popover.Portal>
    </Popover.Root>
  );
}
