// Paper/marketing bots that should be invisible throughout the app.
// Only shown on dedicated pages (e.g., /layla).
export const PAPER_BOTS = new Set(['layla', 'paper', 'demo']);

// Helper: returns true if a bot name is a paper/marketing bot
export function isPaperBot(name) {
  return PAPER_BOTS.has((name || '').toLowerCase());
}

