import { motion } from 'framer-motion';
import useReducedMotion from '@/hooks/useReducedMotion';

const pageVariants = {
  initial: { opacity: 0, y: 8 },
  animate: { opacity: 1, y: 0 },
  exit:    { opacity: 0, y: -8 },
};

const pageTransition = {
  duration: 0.2,
  ease: [0.4, 0, 0.2, 1],
};

const noMotionVariants = {
  initial: { opacity: 1, y: 0 },
  animate: { opacity: 1, y: 0 },
  exit:    { opacity: 1, y: 0 },
};

const noMotionTransition = { duration: 0 };

/**
 * Wrap any page component for smooth fade+slide entrance.
 * Respects prefers-reduced-motion — skips animations when enabled.
 * Usage: <AnimatedPage><YourPageContent /></AnimatedPage>
 */
export default function AnimatedPage({ children, className = '' }) {
  const reducedMotion = useReducedMotion();

  return (
    <motion.div
      variants={reducedMotion ? noMotionVariants : pageVariants}
      initial="initial"
      animate="animate"
      exit="exit"
      transition={reducedMotion ? noMotionTransition : pageTransition}
      className={className}
      style={{ width: '100%', minHeight: '100%' }}
    >
      {children}
    </motion.div>
  );
}

// Stagger container for lists of cards/items
export const staggerContainer = {
  animate: {
    transition: {
      staggerChildren: 0.04,
    },
  },
};

export const staggerItem = {
  initial: { opacity: 0, y: 12 },
  animate: { opacity: 1, y: 0, transition: { duration: 0.2, ease: [0.4, 0, 0.2, 1] } },
};

// Scale-on-tap for interactive cards
export const tapScale = {
  whileTap: { scale: 0.98 },
  transition: { duration: 0.1 },
};
