/**
 * AURA ALPHA -- useClientCompute Hook
 * ====================================
 * Manages the background Web Worker that processes computation jobs
 * using the user's own CPU. Starts automatically when authenticated,
 * stops on sign-out or unmount.
 *
 * Usage:
 *   const { computing, stats, error } = useClientCompute();
 *
 * Exports:
 *   computing  — boolean, true when the worker is running
 *   stats      — { jobsCompleted, cpuTimeMs, lastJobAt }
 *   error      — string or null
 *   start()    — manually start the worker
 *   stop()     — manually stop the worker
 */
import { useState, useEffect, useRef, useCallback } from 'react';
import { getApiBase } from '../utils/platform';

export function useClientCompute() {
  const workerRef = useRef(null);
  const [computing, setComputing] = useState(false);
  const [stats, setStats] = useState({
    jobsCompleted: 0,
    jobsFailed: 0,
    totalCpuTimeMs: 0,
    lastJobAt: null,
  });
  const [error, setError] = useState(null);

  // Handle messages from the worker
  const handleMessage = useCallback((e) => {
    const { type, data } = e.data;

    switch (type) {
      case 'status':
        setComputing(data.running);
        setStats({
          jobsCompleted: data.jobsCompleted || 0,
          jobsFailed: data.jobsFailed || 0,
          totalCpuTimeMs: data.totalCpuTimeMs || 0,
          lastJobAt: data.lastJobAt || null,
        });
        break;

      case 'job_completed':
        setStats(prev => ({
          ...prev,
          jobsCompleted: prev.jobsCompleted + 1,
          totalCpuTimeMs: prev.totalCpuTimeMs + (data.cpuTimeMs || 0),
          lastJobAt: new Date().toISOString(),
        }));
        break;

      case 'job_failed':
        setStats(prev => ({
          ...prev,
          jobsFailed: prev.jobsFailed + 1,
        }));
        break;

      case 'error':
        setError(data.message);
        if (data.message === 'Authentication expired') {
          setComputing(false);
        }
        break;

      case 'idle':
        // Worker is idle, waiting for next poll -- no action needed
        break;

      default:
        break;
    }
  }, []);

  // Start the worker
  const start = useCallback(() => {
    const token = localStorage.getItem('aura_token');
    if (!token || workerRef.current) return;

    try {
      const worker = new Worker(
        new URL('../workers/computeWorker.js', import.meta.url),
        { type: 'module' }
      );
      worker.addEventListener('message', handleMessage);
      worker.addEventListener('error', (err) => {
        setError(err.message || 'Worker error');
      });

      worker.postMessage({
        type: 'start',
        payload: {
          token,
          apiBase: getApiBase(),
        },
      });

      workerRef.current = worker;
      setComputing(true);
      setError(null);
    } catch (err) {
      setError(`Failed to start compute worker: ${err.message}`);
    }
  }, [handleMessage]);

  // Stop the worker
  const stop = useCallback(() => {
    if (workerRef.current) {
      workerRef.current.postMessage({ type: 'stop' });
      workerRef.current.terminate();
      workerRef.current = null;
      setComputing(false);
    }
  }, []);

  // Auto-start when authenticated, auto-stop on unmount
  useEffect(() => {
    const token = localStorage.getItem('aura_token');
    if (token) {
      // Small delay so initial page render is not blocked
      const timer = setTimeout(start, 2000);
      return () => {
        clearTimeout(timer);
        stop();
      };
    }
    return stop;
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  // Stop worker when token is removed (sign out)
  useEffect(() => {
    const onStorage = (e) => {
      if (e.key === 'aura_token' && !e.newValue) {
        stop();
      }
    };
    window.addEventListener('storage', onStorage);
    return () => window.removeEventListener('storage', onStorage);
  }, [stop]);

  return {
    computing,
    stats,
    error,
    start,
    stop,
    worker: workerRef.current,
  };
}

export default useClientCompute;
