/**
 * useSubscriptionCheck — Periodic subscription/tier verification hook.
 *
 * Polls /api/billing/overview every 5 minutes to verify the user's subscription
 * is still active. If the subscription has expired:
 *   - Sets `expired` to true
 *   - Emits a window event for upgrade modals
 *   - Disables live trading features (paper trading still works)
 *
 * If the API is unreachable, the hook degrades gracefully — it does NOT
 * lock the user out. The last known state is preserved.
 */
import { useState, useEffect, useCallback, useRef } from 'react';
import { getApiBase } from '../utils/platform';

const CHECK_INTERVAL_MS = 5 * 60 * 1000; // 5 minutes
const STORAGE_KEY = 'aura_sub_status';

function authHeaders() {
  try {
    const token = localStorage.getItem('aura_token');
    return token ? { Authorization: `Bearer ${token}` } : {};
  } catch {
    return {};
  }
}

/**
 * Read cached subscription status from localStorage.
 * Returns null if nothing is stored.
 */
function getCachedStatus() {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    return raw ? JSON.parse(raw) : null;
  } catch {
    return null;
  }
}

/**
 * Persist subscription status snapshot to localStorage.
 */
function setCachedStatus(status) {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(status));
  } catch { /* quota exceeded — non-critical */ }
}

export default function useSubscriptionCheck() {
  const [status, setStatus] = useState(() => {
    const cached = getCachedStatus();
    return {
      tier: cached?.tier || 'explorer',
      expired: cached?.expired || false,
      expiresAt: cached?.expiresAt || null,
      trialActive: cached?.trialActive || false,
      trialDaysLeft: cached?.trialDaysLeft || 0,
      apiReachable: true,
      loading: true,
      lastCheck: cached?.lastCheck || null,
    };
  });

  const mountedRef = useRef(true);

  const checkSubscription = useCallback(async () => {
    const token = localStorage.getItem('aura_token');
    if (!token) {
      // Not logged in — nothing to check
      if (mountedRef.current) {
        setStatus(prev => ({ ...prev, loading: false }));
      }
      return;
    }

    try {
      // Try /billing/overview first (has the most subscription detail)
      const resp = await fetch(`${getApiBase()}/billing/overview`, {
        headers: authHeaders(),
        signal: AbortSignal.timeout?.(10000), // 10s timeout
      });

      if (!resp.ok) {
        // Try fallback to /auth/me for basic tier info
        const meResp = await fetch(`${getApiBase()}/auth/me`, {
          headers: authHeaders(),
          signal: AbortSignal.timeout?.(10000),
        });

        if (meResp.ok) {
          const meData = await meResp.json();
          const tier = meData.subscription_tier || meData.tier || 'explorer';
          const now = Date.now();
          const newStatus = {
            tier,
            expired: false,
            expiresAt: null,
            trialActive: false,
            trialDaysLeft: 0,
            apiReachable: true,
            loading: false,
            lastCheck: now,
          };
          if (mountedRef.current) {
            setStatus(newStatus);
            setCachedStatus(newStatus);
          }
          return;
        }

        // Both endpoints failed but API is up — don't lock out
        if (mountedRef.current) {
          setStatus(prev => ({ ...prev, apiReachable: true, loading: false }));
        }
        return;
      }

      const data = await resp.json();
      const now = Date.now();

      // Determine expiration
      const subStatus = data.subscription_status || data.status || 'active';
      const expiresAt = data.current_period_end || data.expires_at || data.expiration || null;
      const tier = data.tier || data.subscription_tier || 'explorer';
      const trialEnd = data.trial_end || data.trial_ends_at || null;

      // Check if expired
      let expired = false;
      if (subStatus === 'expired' || subStatus === 'canceled' || subStatus === 'past_due') {
        expired = true;
      } else if (expiresAt) {
        const expireTs = new Date(expiresAt).getTime();
        if (expireTs < now) {
          expired = true;
        }
      }

      // Trial detection
      let trialActive = false;
      let trialDaysLeft = 0;
      if (trialEnd) {
        const trialEndTs = new Date(trialEnd).getTime();
        if (trialEndTs > now) {
          trialActive = true;
          trialDaysLeft = Math.ceil((trialEndTs - now) / (1000 * 60 * 60 * 24));
        }
      }
      if (subStatus === 'trialing') {
        trialActive = true;
      }

      const newStatus = {
        tier,
        expired,
        expiresAt,
        trialActive,
        trialDaysLeft,
        apiReachable: true,
        loading: false,
        lastCheck: now,
      };

      if (mountedRef.current) {
        setStatus(newStatus);
        setCachedStatus(newStatus);

        // Dispatch event for other components (e.g., upgrade modals)
        if (expired) {
          window.dispatchEvent(new CustomEvent('aura:subscription-expired', {
            detail: { tier, expiresAt },
          }));
        }
      }
    } catch (err) {
      // Network error — API unreachable. Graceful degradation: keep last known state.
      if (mountedRef.current) {
        setStatus(prev => ({
          ...prev,
          apiReachable: false,
          loading: false,
        }));
      }
    }
  }, []);

  useEffect(() => {
    mountedRef.current = true;

    // Initial check
    checkSubscription();

    // Periodic check every 5 minutes
    const interval = setInterval(checkSubscription, CHECK_INTERVAL_MS);

    return () => {
      mountedRef.current = false;
      clearInterval(interval);
    };
  }, [checkSubscription]);

  return {
    /** Current tier string (e.g., 'explorer', 'trader', 'pro') */
    tier: status.tier,
    /** Whether the subscription has expired */
    expired: status.expired,
    /** ISO date string of expiration, if known */
    expiresAt: status.expiresAt,
    /** Whether a trial is currently active */
    trialActive: status.trialActive,
    /** Days remaining in trial */
    trialDaysLeft: status.trialDaysLeft,
    /** Whether the API was reachable on last check */
    apiReachable: status.apiReachable,
    /** Whether the initial check is still in progress */
    loading: status.loading,
    /** Timestamp of last successful check */
    lastCheck: status.lastCheck,
    /** Whether live trading should be disabled (expired = yes, paper trading still allowed) */
    liveTradingDisabled: status.expired,
    /** Force a re-check now */
    recheck: checkSubscription,
  };
}
