import { useState, useEffect, useCallback } from 'react';
import { api } from '../utils/api';
import { PAPER_BOTS, BOT_METADATA_KEYS } from '../utils/constants';

// No hardcoded fallback bots — users only see bots they've configured

function mergeBotData(configBots, telemetryBots, equityHistory) {
  const tel = telemetryBots || {};
  const eqHist = equityHistory || {};

  return configBots.map(bot => {
    const botTel = tel[bot.bot_name] || {};
    const payload = botTel.payload || {};
    const eq = bot.equity || payload.equity || {};

    // Use the enriched data from /bots endpoint (has computed PnL, risk, trade counts)
    const dayPnl = (typeof eq === 'object' ? (eq.day ?? 0) : 0);
    const weekPnl = (typeof eq === 'object' ? (eq.week ?? 0) : 0);
    const monthPnl = (typeof eq === 'object' ? (eq.month ?? 0) : 0);
    const dayPct = (typeof eq === 'object' ? (eq.day_pct ?? null) : null);
    const weekPct = (typeof eq === 'object' ? (eq.week_pct ?? null) : null);
    const monthPct = (typeof eq === 'object' ? (eq.month_pct ?? null) : null);

    // Build equity curve from history data
    const _hist = eqHist[bot.bot_name];
    const historyPoints = Array.isArray(_hist) ? _hist : [];
    const equityCurve = historyPoints.map(p => p.equity ?? p.value ?? p);

    // Filled trade count from enriched backend data
    const filledTrades = bot.trade_count ?? 0;
    const totalTrades = bot.trade_count_total ?? payload.trades?.length ?? 0;
    const cancelledTrades = bot.trade_count_cancelled ?? 0;

    return {
      ...bot,
      name: (bot.display_name || bot.bot_name || '').toUpperCase(),
      status: botTel.status || bot.status || 'UNKNOWN',
      lastHeartbeat: botTel.last_heartbeat || bot.last_heartbeat || null,
      equity: typeof eq === 'object' ? (eq.current ?? 0) : (eq ?? 0),
      dayPnl,
      weekPnl,
      monthPnl,
      pnl: { day: dayPnl, week: weekPnl, month: monthPnl },
      pnlPct: { day: dayPct, week: weekPct, month: monthPct },
      positions: bot.position_count ?? payload.positions?.length ?? 0,
      positionDetails: bot.position_details || [],
      trades: filledTrades,
      tradesTotalOrders: totalTrades,
      tradesCancelled: cancelledTrades,
      strategies: bot.strategies || [],
      mode: bot.mode || payload.mode || 'DRY_RUN',
      engine: bot.engine || null,
      equityCurve,
      riskTier: bot.risk_tier || null,
      riskReasons: bot.risk_reasons || [],
      client_id: bot.client_id,
    };
  });
}

// Use shared BOT_METADATA_KEYS from constants (aliased for backward compat)
const TELEMETRY_META_KEYS = BOT_METADATA_KEYS;

function botsFromTelemetry(telData, eqHist) {
  const botsObj = telData?.bots;
  if (!botsObj || typeof botsObj !== 'object') return null;

  return Object.entries(botsObj)
    .filter(([name, info]) => !TELEMETRY_META_KEYS.has(name) && !PAPER_BOTS.has(name.toLowerCase()) && info && typeof info === 'object')
    .map(([name, info]) => {
      const payload = info.payload || {};
      const eq = payload.equity || {};
      const _h = eqHist[name];
      const historyPoints = (Array.isArray(_h) ? _h : []).filter(p => p.equity != null && isFinite(p.equity));
      const equityCurve = historyPoints.map(p => p.equity ?? p.value ?? p);

      return {
        bot_name: name,
        display_name: name.toUpperCase(),
        name: name.toUpperCase(),
        status: info.status || 'OK',
        last_heartbeat: info.last_heartbeat || null,
        mode: payload.mode || 'LIVE',
        enabled: payload.enabled ?? true,
        equity: { current: eq.current ?? 0, day: eq.day_pnl ?? eq.day ?? 0, week: eq.week ?? 0, month: eq.month ?? 0 },
        position_count: Array.isArray(payload.positions) ? payload.positions.length : 0,
        position_details: payload.positions || [],
        trade_count: Array.isArray(payload.trades) ? payload.trades.length : 0,
        strategies: payload.strategies || [],
        client_id: payload.targets?.trading_client_id || null,
        color: name === 'alpha' ? '#3FB950' : name === 'beta' ? '#58A6FF' : name === 'paper' ? '#EC4899' : '#BC8CFF',
        engine: payload.engine || null,
        equityCurve,
        risk_tier: null,
        risk_reasons: [],
      };
    });
}

export default function useUserBots(pollMs = 5000) {
  const [bots, setBots] = useState([]);
  const [botColors, setBotColors] = useState({});
  const [loading, setLoading] = useState(true);

  // Fetch everything together: bot config (with enriched data) + equity history
  // Falls back to telemetry when /api/bots returns 401 (no auth)
  const fetchAll = useCallback(async () => {
    let botsData, telData, eqData;
    try {
      [botsData, telData, eqData] = await Promise.all([
        api('/bots', { silent: true }).catch(() => null),
        api('/telemetry/latest', { silent: true }).catch(() => null),
        api('/telemetry/equity-history', { silent: true }).catch(() => null),
      ]);
    } catch (err) {
      console.error('[useUserBots] fetch error:', err);
      setLoading(false);
      return;
    }

    const eqHist = (eqData && typeof eqData === 'object' && !eqData.error) ? eqData : {};

    // Primary path: use /api/bots if available (filter paper/marketing bots)
    const rawConfig = botsData?.bots?.length > 0 ? botsData.bots : null;
    const config = rawConfig ? rawConfig.filter(b => !PAPER_BOTS.has((b.bot_name || '').toLowerCase())) : null;

    if (config && config.length > 0) {
      const colors = {};
      config.forEach(b => { colors[b.bot_name] = b.color; colors[(b.display_name || '').toUpperCase()] = b.color; });
      setBotColors(colors);
      const merged = mergeBotData(config, telData?.bots || {}, eqHist);
      setBots(merged);
    } else {
      // Fallback: build bots from telemetry data (when /api/bots is auth-gated)
      const telBots = botsFromTelemetry(telData, eqHist);
      if (telBots && telBots.length > 0) {
        const colors = {};
        telBots.forEach(b => { colors[b.bot_name] = b.color; colors[b.display_name] = b.color; });
        setBotColors(colors);
        const merged = mergeBotData(telBots, telData?.bots || {}, eqHist);
        setBots(merged);
      } else if (botsData !== null) {
        setBotColors({});
        setBots([]);
      }
      // If botsData is null (401 handled), keep existing state
    }
    setLoading(false);
  }, []);

  useEffect(() => {
    fetchAll();
    const id = setInterval(fetchAll, pollMs);
    return () => clearInterval(id);
  }, [fetchAll, pollMs]);

  return { bots, botColors, loading };
}
