import { useEffect, useRef, useState } from "react";

/**
 * Polls a function at a given interval.
 * Automatically pauses when the browser tab is hidden to save resources.
 * Resumes and fires immediately when the tab becomes visible again.
 */
export function usePoll(fn, { intervalMs = 15000, immediate = true, enabled = true } = {}) {
  const [data, setData] = useState(null);
  const [err, setErr] = useState("");
  const [loading, setLoading] = useState(true);
  const alive = useRef(true);
  const fnRef = useRef(fn);
  const intervalRef = useRef(null);
  fnRef.current = fn;

  useEffect(() => {
    alive.current = true;
    return () => { alive.current = false; };
  }, []);

  useEffect(() => {
    if (!enabled) {
      setLoading(false);
      return;
    }

    const tick = async () => {
      // Skip polling when tab is hidden
      if (document.hidden) return;
      try {
        const v = await fnRef.current();
        if (!alive.current) return;
        setData(v);
        setErr("");
      } catch (e) {
        if (!alive.current) return;
        setErr("poll_failed");
      } finally {
        if (!alive.current) return;
        setLoading(false);
      }
    };

    const startInterval = () => {
      if (intervalRef.current) clearInterval(intervalRef.current);
      intervalRef.current = setInterval(tick, intervalMs);
    };

    // On visibility change: resume polling + fire immediately
    const onVisibility = () => {
      if (!document.hidden && alive.current) {
        tick();
        startInterval();
      }
    };

    if (immediate) tick();
    startInterval();
    document.addEventListener("visibilitychange", onVisibility);

    return () => {
      if (intervalRef.current) clearInterval(intervalRef.current);
      document.removeEventListener("visibilitychange", onVisibility);
    };
  }, [intervalMs, immediate, enabled]);

  return { data, err, loading };
}
