/**
 * useCompetitionUpgrades — Hook that checks competition state and triggers
 * upgrade nudges at the RIGHT moments (rank achieved, XP milestone, streak,
 * founding spots urgency, rank drop).
 *
 * Works alongside (never replaces) useUpgradeNudge and SmartUpgradeNudge.
 *
 * Usage:
 *   const { nudge, dismiss } = useCompetitionUpgrades(userTier);
 *   <CompetitionUpgradeModal nudge={nudge} onDismiss={dismiss} />
 */
import { useState, useEffect, useCallback } from 'react';
import { api, apiPost } from '../utils/api';

const NUDGE_COOLDOWN = 24 * 60 * 60 * 1000; // 24 hours between nudges

function hasSeenRecently(key) {
  try {
    const ts = localStorage.getItem(`aura_nudge_${key}`);
    return ts && Date.now() - parseInt(ts, 10) < NUDGE_COOLDOWN;
  } catch {
    return false;
  }
}

function markSeen(key) {
  try {
    localStorage.setItem(`aura_nudge_${key}`, Date.now().toString());
  } catch {}
}

export function useCompetitionUpgrades(userTier) {
  const [nudge, setNudge] = useState(null);

  const checkTriggers = useCallback(async () => {
    // Only nudge free/low tier users
    if (!userTier || !['explorer', 'free', 'starter', ''].includes(userTier)) return;

    try {
      const [profile, rankData, spots] = await Promise.all([
        api('/gamification/profile', { silent: true }).catch(() => null),
        api('/rankings/me', { silent: true }).catch(() => null),
        api('/auth/founding-spots', { silent: true }).catch(() => null),
      ]);

      // Trigger 1: Leaderboard rank achieved — "You're ranked! Upgrade to climb higher"
      if (rankData?.rank && rankData.rank <= 50 && !hasSeenRecently('rank_upgrade')) {
        markSeen('rank_upgrade');
        setNudge({
          type: 'rank_achievement',
          title: `You're Ranked #${rankData.rank}`,
          message: `You're in the top ${rankData.percentile?.toFixed(0) || 25}%. Upgrade to unlock all 83 strategies and climb higher.`,
          cta: 'Unlock Full Access',
          tier: 'trader',
        });
        return;
      }

      // Trigger 2: XP tier milestone — "You just reached Trader tier! Unlock the perks"
      const tierName = typeof profile?.tier === 'object' ? (profile.tier.current_tier || 'rookie') : (profile?.tier || 'rookie');
      if (tierName && tierName !== 'rookie' && !hasSeenRecently(`xp_tier_${tierName}`)) {
        markSeen(`xp_tier_${tierName}`);
        setNudge({
          type: 'xp_milestone',
          title: `${tierName.charAt(0).toUpperCase() + tierName.slice(1)} Tier Reached!`,
          message: `You've earned ${profile.xp?.toLocaleString() || 0} XP. Upgrade your subscription to unlock the perks of your ${tierName} tier.`,
          cta: 'Activate Tier Perks',
          tier: 'trader',
        });
        return;
      }

      // Trigger 3: Streak milestone — "7-day streak! You're on fire"
      if (profile?.streak_days >= 7 && !hasSeenRecently('streak_upgrade')) {
        markSeen('streak_upgrade');
        setNudge({
          type: 'streak_milestone',
          title: `${profile.streak_days}-Day Streak!`,
          message: `You're consistently active. Upgrade to run multiple agents and automate your strategies.`,
          cta: 'Scale Your Trading',
          tier: 'trader',
        });
        return;
      }

      // Trigger 4: Founding spots urgency — "Only X spots left"
      if (spots?.remaining && spots.remaining <= 20 && !hasSeenRecently('founding_urgency')) {
        markSeen('founding_urgency');
        setNudge({
          type: 'founding_urgency',
          title: `Only ${spots.remaining} Founding Spots Left`,
          message: `Founding members get lifetime access at launch pricing. Don't miss out.`,
          cta: 'Claim Your Spot',
          tier: 'trader',
        });
        return;
      }

      // Trigger 5: Being passed on leaderboard
      if (rankData?.delta && rankData.delta < -3 && !hasSeenRecently('rank_drop')) {
        markSeen('rank_drop');
        setNudge({
          type: 'rank_drop',
          title: `You Dropped ${Math.abs(rankData.delta)} Spots`,
          message: `Top traders are using advanced strategies. Upgrade to access all 83 strategies and compete at full power.`,
          cta: 'Unlock All Strategies',
          tier: 'trader',
        });
        return;
      }

    } catch {
      // Silent — never break the app for a nudge
    }
  }, [userTier]);

  useEffect(() => {
    // Check on mount + every 5 minutes
    checkTriggers();
    const interval = setInterval(checkTriggers, 5 * 60 * 1000);
    return () => clearInterval(interval);
  }, [checkTriggers]);

  const dismiss = useCallback(() => {
    if (nudge) {
      // Track dismissal
      apiPost('/analytics/event', {
        event: 'nudge_dismissed',
        properties: { type: nudge.type, tier: nudge.tier },
      }).catch(() => {});
    }
    setNudge(null);
  }, [nudge]);

  return { nudge, dismiss };
}
