import { createContext, useContext, useEffect, useRef, useState } from "react";
import { getApiBase } from '../../utils/platform';

const Ctx = createContext(null);

export function BacktestResultsProvider({ children }) {
  const [results, setResults] = useState(null);
  const [loading, setLoading] = useState(true);
  const alive = useRef(true);

  useEffect(() => {
    alive.current = true;
    const poll = async () => {
      try {
        const r = await fetch(`${getApiBase()}/backtest/results`);
        if (!r.ok) throw new Error(r.status);
        const data = await r.json();
        if (alive.current) {
          setResults(data);
          setLoading(false);
        }
      } catch {
        if (alive.current) setLoading(false);
      }
    };
    poll();
    const id = setInterval(poll, 30000);
    return () => { alive.current = false; clearInterval(id); };
  }, []);

  return <Ctx.Provider value={{ results, loading }}>{children}</Ctx.Provider>;
}

export function useBacktestResults() {
  const v = useContext(Ctx);
  if (!v) throw new Error("useBacktestResults must be inside BacktestResultsProvider");
  return v;
}
