import { createContext, useContext, useState, useCallback, useRef, useEffect } from 'react';
import { tokens } from '../../styles/tokens';

// ─── Toast Context ──────────────────────────────────────────────────────────

const ToastContext = createContext(null);

const TOAST_TYPES = {
  success: { color: tokens.color.green, icon: 'check', bg: tokens.color.greenDim },
  error:   { color: tokens.color.red,   icon: 'x',     bg: tokens.color.redDim },
  info:    { color: tokens.color.blue,  icon: 'i',     bg: 'rgba(88,166,255,0.15)' },
  warning: { color: tokens.color.amber, icon: '!',     bg: 'rgba(210,153,34,0.15)' },
};

const MAX_TOASTS = 3;
const AUTO_DISMISS_MS = 3000;

let toastId = 0;

/**
 * ToastProvider - Wrap your app with this to enable useToast().
 */
export function ToastProvider({ children }) {
  const [toasts, setToasts] = useState([]);
  const timers = useRef({});

  const removeToast = useCallback((id) => {
    setToasts(prev => prev.filter(t => t.id !== id));
    if (timers.current[id]) {
      clearTimeout(timers.current[id]);
      delete timers.current[id];
    }
  }, []);

  const addToast = useCallback(({ type = 'info', title, message, duration = AUTO_DISMISS_MS }) => {
    const id = ++toastId;
    setToasts(prev => {
      const next = [...prev, { id, type, title, message }];
      // Trim to max
      if (next.length > MAX_TOASTS) return next.slice(next.length - MAX_TOASTS);
      return next;
    });

    // Auto-dismiss
    if (duration > 0) {
      timers.current[id] = setTimeout(() => removeToast(id), duration);
    }

    return id;
  }, [removeToast]);

  // ── Bridge: listen for global API toast events from api.js ──
  // This allows non-React code (api.js) to trigger toasts without importing context.
  useEffect(() => {
    const handler = (e) => {
      const { type, title, message } = e.detail || {};
      addToast({ type: type || 'error', title, message, duration: 5000 });
    };
    window.addEventListener('aura:api-toast', handler);
    return () => window.removeEventListener('aura:api-toast', handler);
  }, [addToast]);

  // ── Catch unhandled promise rejections (fetch errors that escape try/catch) ──
  useEffect(() => {
    const handler = (e) => {
      // Only catch fetch/network errors, not all promise rejections
      const msg = e.reason?.message || '';
      const isFetchError =
        msg.includes('Failed to fetch') ||
        msg.includes('NetworkError') ||
        msg.includes('Network request failed') ||
        msg.includes('Load failed');
      if (isFetchError) {
        e.preventDefault(); // Prevent console error
        addToast({
          type: 'error',
          title: 'Network error',
          message: 'A request failed. Check your connection.',
          duration: 5000,
        });
      }
    };
    window.addEventListener('unhandledrejection', handler);
    return () => window.removeEventListener('unhandledrejection', handler);
  }, [addToast]);

  // Clean up timers on unmount
  useEffect(() => {
    return () => {
      Object.values(timers.current).forEach(clearTimeout);
    };
  }, []);

  return (
    <ToastContext.Provider value={{ addToast, removeToast }}>
      {children}
      {/* Toast container */}
      <div
        role="status"
        aria-live="polite"
        aria-label="Notifications"
        style={{
          position: 'fixed',
          top: 80,
          right: 16,
          zIndex: 10000,
          display: 'flex',
          flexDirection: 'column',
          gap: 8,
          maxWidth: 380,
          pointerEvents: 'none',
        }}
      >
        <style>{toastKeyframes}</style>
        {toasts.map((t) => {
          const cfg = TOAST_TYPES[t.type] || TOAST_TYPES.info;
          return (
            <div
              key={t.id}
              style={{
                display: 'flex',
                alignItems: 'flex-start',
                gap: 10,
                padding: '12px 16px',
                background: tokens.color.surface,
                border: `1px solid ${cfg.color}40`,
                borderLeft: `4px solid ${cfg.color}`,
                borderRadius: tokens.radius.md,
                boxShadow: tokens.shadow.md,
                animation: 'toastSlideIn 0.3s ease-out',
                pointerEvents: 'auto',
              }}
            >
              {/* Icon circle */}
              <div style={{
                width: 22,
                height: 22,
                borderRadius: tokens.radius.full,
                background: cfg.bg,
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                fontSize: 11,
                fontWeight: 700,
                color: cfg.color,
                flexShrink: 0,
                fontFamily: tokens.font.mono,
              }}>
                {cfg.icon === 'check' ? '\u2713' : cfg.icon === 'x' ? '\u2715' : cfg.icon}
              </div>

              {/* Content */}
              <div style={{ flex: 1, minWidth: 0 }}>
                {t.title && (
                  <div style={{
                    fontFamily: tokens.font.sans,
                    fontSize: tokens.fontSize.base,
                    fontWeight: tokens.fontWeight.semibold,
                    color: tokens.color.text,
                    marginBottom: 2,
                  }}>
                    {t.title}
                  </div>
                )}
                {t.message && (
                  <div style={{
                    fontFamily: tokens.font.sans,
                    fontSize: tokens.fontSize.sm,
                    color: tokens.color.textSecondary,
                    lineHeight: 1.4,
                  }}>
                    {t.message}
                  </div>
                )}
              </div>

              {/* Dismiss */}
              <button
                onClick={() => removeToast(t.id)}
                style={{
                  background: 'none',
                  border: 'none',
                  color: tokens.color.textMuted,
                  cursor: 'pointer',
                  fontSize: 16,
                  fontWeight: 700,
                  padding: '0 2px',
                  lineHeight: 1,
                  flexShrink: 0,
                }}
                aria-label="Dismiss"
              >
                \u00d7
              </button>
            </div>
          );
        })}
      </div>
    </ToastContext.Provider>
  );
}

/**
 * useToast - Hook to show toast notifications.
 *
 * Usage:
 *   const toast = useToast();
 *   toast.success('Saved!');
 *   toast.error('Failed', 'Could not connect');
 *   toast.info('Tip', 'Try the new feature');
 *   toast.warning('Caution', 'Rate limit approaching');
 */
export function useToast() {
  const ctx = useContext(ToastContext);
  if (!ctx) throw new Error('useToast must be used within a <ToastProvider>');

  const { addToast, removeToast } = ctx;
  return {
    success: (title, message) => addToast({ type: 'success', title, message }),
    error:   (title, message) => addToast({ type: 'error',   title, message }),
    info:    (title, message) => addToast({ type: 'info',    title, message }),
    warning: (title, message) => addToast({ type: 'warning', title, message }),
    dismiss: removeToast,
    add: addToast,
  };
}

const toastKeyframes = `
@keyframes toastSlideIn {
  from { opacity: 0; transform: translateX(40px); }
  to   { opacity: 1; transform: translateX(0); }
}
`;

export default ToastProvider;
