// ── Status Pills ────────────────────────────────────────────────────────────
function StatusPillsBar() {
  const [health, setHealth] = useState(null);
  const [sources, setSources] = useState(null);
  const [lastHealthUpdate, setLastHealthUpdate] = useState(null);
  const [apiReachable, setApiReachable] = useState(true);

  useEffect(() => {
    let m = true;
    const poll = () => {
      const ts = Date.now();
      fetch(`${getApiBase()}/health`).then(r => r.json()).then(d => {
        if (m) { setHealth(d); setLastHealthUpdate(ts); setApiReachable(true); }
      }).catch(() => { if (m) setApiReachable(false); });
      fetch(`${getApiBase()}/control/health`).then(r => r.json()).then(d => { if (m) setHealth(prev => ({ ...prev, ...d })); }).catch(() => {});
      fetch(`${getApiBase()}/system/sources`).then(r => r.json()).then(d => { if (m) setSources(d); }).catch(() => {});
    };
    poll();
    const iv = setInterval(poll, 30000);  // 30s — health changes slowly, was 8s
    return () => { m = false; clearInterval(iv); };
  }, []);

  // Stale data detection: if health data is > 60s old, show amber dot on API pill
  const [now, setNow] = useState(Date.now());
  useEffect(() => {
    const iv = setInterval(() => setNow(Date.now()), 5000);
    return () => clearInterval(iv);
  }, []);
  const healthAge = lastHealthUpdate ? now - lastHealthUpdate : null;
  const isStale = healthAge !== null && healthAge > 60000; // > 60s

  const ibkrOk = health?.bots && Object.values(health.bots).some(b => b.status === 'OK');
  const canTrade = health?.can_trade;
  const krakenSrc = sources?.sources?.find(s => s.name === 'Kraken');
  const krakenOk = krakenSrc?.online;
  const cryptoOk = health?.bots?.crypto?.status === 'OK';
  const krakenStatus = krakenOk ? 'online' : cryptoOk ? 'degraded' : 'offline';

  // API status: green = reachable + ok, amber = reachable but stale, red = unreachable
  const apiStatus = !apiReachable ? 'offline' : isStale ? 'degraded' : health?.status === 'ok' ? 'online' : 'offline';
  const apiTitle = !apiReachable ? 'API unreachable'
    : isStale ? `API data stale (${Math.round((healthAge || 0) / 1000)}s ago)`
    : health?.status === 'ok' ? 'API healthy' : 'API unhealthy';

  return (
    <div className="status-pills" role="status" aria-live="polite" aria-label="Connection status">
      <GatewayPopover>
        <button className="status-pill" style={{ background: 'none', border: 'none', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: 4, padding: 0 }} aria-label={`IBKR gateway ${ibkrOk ? 'connected' : 'disconnected'}`}>
          <span className={`status-dot ${ibkrOk ? 'online' : 'offline'}`} />
          <span className="status-pill-label">IBKR</span>
        </button>
      </GatewayPopover>
      <GatewayPopover>
        <button className="status-pill" style={{ background: 'none', border: 'none', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: 4, padding: 0 }} aria-label={`Kraken exchange ${krakenStatus}`}>
          <span className={`status-dot ${krakenStatus}`} />
          <span className="status-pill-label">KRAKEN</span>
        </button>
      </GatewayPopover>
      <div className="status-pill" title={apiTitle} aria-label={apiTitle}>
        <span className={`status-dot ${apiStatus}`} />
        <span className="status-pill-label">API</span>
      </div>
      <div className="status-pill" aria-label={`Trading ${canTrade ? 'enabled' : 'disabled'}`}>
        <span className={`status-dot ${canTrade ? 'online' : health?.kill?.enabled ? 'offline' : 'degraded'}`} />
        <span className="status-pill-label">TRADE</span>
      </div>
    </div>
  );
}

// ── Market Timer (client-side) ────────────────────────────────────────────
function getNextMarketEvent() {
  const now = new Date();
  const parts = new Intl.DateTimeFormat('en-US', {
    timeZone: 'America/New_York', hour: 'numeric', minute: 'numeric',
    second: 'numeric', weekday: 'short', hour12: false,
  }).formatToParts(now);
  const get = (type) => parts.find(p => p.type === type)?.value || '';
  const dayMap = { Sun: 0, Mon: 1, Tue: 2, Wed: 3, Thu: 4, Fri: 5, Sat: 6 };
  const day = dayMap[get('weekday')] ?? now.getDay();
  const h = parseInt(get('hour'), 10) || 0;
  const m = parseInt(get('minute'), 10) || 0;
  const s = parseInt(get('second'), 10) || 0;
  const totalSec = h * 3600 + m * 60 + s;
  const openSec = 9 * 3600 + 30 * 60;
  const closeSec = 16 * 3600;
  if (day >= 1 && day <= 5 && totalSec >= openSec && totalSec < closeSec) {
    return { isOpen: true, label: 'MARKET OPEN', event: 'Close', remaining: closeSec - totalSec, color: '#22C55E' };
  }
  let secsUntilOpen = 0;
  if (day >= 1 && day <= 5 && totalSec < openSec) secsUntilOpen = openSec - totalSec;
  else if (day === 5 && totalSec >= closeSec) secsUntilOpen = (2 * 86400) + openSec + (86400 - totalSec);
  else if (day === 6) secsUntilOpen = 86400 + openSec + (86400 - totalSec);
  else if (day === 0) secsUntilOpen = openSec + (86400 - totalSec);
  else secsUntilOpen = openSec + (86400 - totalSec);
  const isWeekend = day === 0 || day === 6;
  const isPreMarket = day >= 1 && day <= 5 && totalSec >= 4 * 3600 && totalSec < openSec;
  const isAfterHours = day >= 1 && day <= 5 && totalSec >= closeSec && totalSec < 20 * 3600;
  const label = isWeekend ? 'WEEKEND' : isPreMarket ? 'PRE-MARKET' : isAfterHours ? 'AFTER HOURS' : 'CLOSED';
  const color = isPreMarket ? '#60A5FA' : isAfterHours ? '#F59E0B' : '#8B949E';
  return { isOpen: false, label, event: 'Open', remaining: secsUntilOpen, color };
}

function fmtCountdown(secs) {
  if (secs <= 0) return '00:00:00';
  const h = Math.floor(secs / 3600);
  const m = Math.floor((secs % 3600) / 60);
  const s = secs % 60;
  return `${String(h).padStart(2, '0')}:${String(m).padStart(2, '0')}:${String(s).padStart(2, '0')}`;
}

// ── Global Status Bar (unified bottom bar) ────────────────────────────────
function GlobalStatusBar({ isPaper, toggleTradingMode }) {
  const [mkt, setMkt] = useState(getNextMarketEvent);
  const [health, setHealth] = useState(null);
  const [regime, setRegime] = useState(null);
  const [botStatuses, setBotStatuses] = useState({});
  const { computing: clientComputing, stats: computeStats } = useClientCompute();

  // Market timer (every 10s — market events don't change sub-second)
  useEffect(() => {
    const id = setInterval(() => setMkt(getNextMarketEvent()), 10000);
    return () => clearInterval(id);
  }, []);

  // Health + regime polling (15s for health, regime piggybacks)
  useEffect(() => {
    let m = true;
    const poll = async () => {
      try {
        const [sysH, telemetry, ctrlH, sources, regimeData] = await Promise.all([
          fetch(`${getApiBase()}/system/health`).then(r => r.json()).catch(() => null),
          fetch(`${getApiBase()}/telemetry/latest`).then(r => r.json()).catch(() => null),
          fetch(`${getApiBase()}/control/health`).then(r => r.json()).catch(() => null),
          fetch(`${getApiBase()}/system/sources`).then(r => r.json()).catch(() => null),
          fetch(`${getApiBase()}/regime/current`).then(r => r.json()).catch(() => null),
        ]);
        if (!m) return;

        // IBKR + Kraken + API + Trade status
        const ibkrOk = ctrlH?.bots && Object.values(ctrlH.bots).some(b => b.status === 'OK');
        const krakenSrc = sources?.sources?.find(s => s.name === 'Kraken');
        const krakenOk = krakenSrc?.online;
        const cryptoOk = ctrlH?.bots?.crypto?.status === 'OK';
        const apiOk = !!sysH;
        const canTrade = ctrlH?.can_trade;

        // Gateway status
        const gwFile = sysH?.gateway?.connected ?? sysH?.ibkr_gateway ?? sysH?.gateway ?? ctrlH?.gateway ?? false;
        const botsRaw = telemetry?.bots || {};
        const BOT_META = new Set(['gateway_connected', 'accounts', 'equity', 'position_count', 'trade_count']);
        const PAPER_BOTS = new Set(['layla', 'paper', 'demo']);
        const bots = {};
        Object.entries(botsRaw).forEach(([name, info]) => {
          if (BOT_META.has(name) || PAPER_BOTS.has(name.toLowerCase())) return;
          if (!info || typeof info !== 'object' || Array.isArray(info)) return;
          const lastHb = info?.last_heartbeat || info?.payload?.last_heartbeat;
          if (!lastHb) { bots[name.toUpperCase()] = 'red'; return; }
          const ts = typeof lastHb === 'number' ? lastHb * 1000 : new Date(lastHb).getTime();
          const ageMin = isFinite(ts) ? (Date.now() - ts) / 60000 : 999;
          bots[name.toUpperCase()] = ageMin < 5 ? 'green' : ageMin < 15 ? 'yellow' : 'red';
        });
        const botsAlive = Object.values(bots).some(s => s === 'green');
        const telGw = botsRaw.gateway_connected ?? false;
        const controlBotsOk = ctrlH?.per_bot_health && Object.values(ctrlH.per_bot_health).some(v => v === true);
        const gwStatus = gwFile || telGw || botsAlive || controlBotsOk;

        setHealth({
          ibkr: ibkrOk ? 'green' : 'red',
          kraken: krakenOk ? 'green' : cryptoOk ? 'yellow' : 'red',
          api: apiOk ? 'green' : 'red',
          gateway: gwStatus ? 'green' : 'red',
          trade: canTrade ? 'green' : ctrlH?.kill?.enabled ? 'red' : 'yellow',
        });
        setBotStatuses(bots);
        if (regimeData && !regimeData.error) setRegime(regimeData);
      } catch { /* silent */ }
    };
    poll();
    const iv = setInterval(poll, 15000);
    return () => { m = false; clearInterval(iv); };
  }, []);

  const dot = (color) => {
    const c = color === 'green' ? '#22C55E' : color === 'yellow' ? '#F59E0B' : '#EF4444';
    return { width: 6, height: 6, borderRadius: '50%', background: c, boxShadow: `0 0 6px ${c}50`, flexShrink: 0 };
  };

  const regimeLabel = regime ? (regime.regime || regime.current || '').replace(/_/g, ' ') : '';
  const regimeConf = regime?.confidence != null ? `${(regime.confidence * 100).toFixed(0)}%` : '';
  const isBull = regimeLabel.includes('bull') || regimeLabel.includes('trending up');
  const isBear = regimeLabel.includes('bear') || regimeLabel.includes('trending down');
  const regimeColor = isBull ? '#22C55E' : isBear ? '#EF4444' : '#60A5FA';

  const mono = "'JetBrains Mono', monospace";
  const divider = { width: 1, height: 16, background: 'rgba(48,54,61,0.5)', flexShrink: 0 };

  return (
    <div className="global-status-bar">
      {/* Market status + countdown */}
      <div className="gsb-section">
        <span style={dot(mkt.isOpen ? 'green' : 'yellow')} />
        <span style={{ color: mkt.color, fontFamily: mono, fontSize: 10, fontWeight: 700, letterSpacing: 0.3 }}>
          {mkt.label}
        </span>
        <span style={{ color: '#8B949E', fontFamily: mono, fontSize: 10 }}>
          {mkt.event} in
        </span>
        <span style={{ color: mkt.color, fontFamily: mono, fontSize: 11, fontWeight: 700 }}>
          {fmtCountdown(mkt.remaining)}
        </span>
      </div>

      <div style={divider} />

      {/* Regime */}
      {regimeLabel && (
        <>
          <div className="gsb-section">
            <span style={dot(isBear ? 'red' : isBull ? 'green' : 'yellow')} />
            <span style={{ color: regimeColor, fontFamily: mono, fontSize: 10, fontWeight: 700, textTransform: 'uppercase', letterSpacing: 0.3 }}>
              {regimeLabel}
            </span>
            {regimeConf && <span style={{ color: '#6B7280', fontFamily: mono, fontSize: 10 }}>{regimeConf}</span>}
          </div>
          <div style={divider} />
        </>
      )}

      {/* Connection + bot dots */}
      <div className="gsb-section">
        {health && ['ibkr', 'kraken', 'api', 'gateway'].map(k => (
          <div key={k} className="gsb-dot-item">
            <span style={dot(health[k])} />
            <span className="gsb-dot-label">{k === 'ibkr' ? 'IBKR' : k === 'kraken' ? 'Kraken' : k === 'api' ? 'API' : 'GW'}</span>
          </div>
        ))}
        {Object.entries(botStatuses).map(([name, status]) => (
          <div key={name} className="gsb-dot-item">
            <span style={dot(status)} />
            <span className="gsb-dot-label">{name}</span>
          </div>
        ))}
      </div>

      <div style={{ flex: 1 }} />

      {/* Client Compute indicator */}
      {clientComputing && (
        <>
          <div className="gsb-section" title={`Client compute: ${computeStats.jobsCompleted} jobs processed, ${(computeStats.totalCpuTimeMs / 1000).toFixed(1)}s CPU`}>
            <span style={{ width: 6, height: 6, borderRadius: '50%', background: '#BC8CFF', boxShadow: '0 0 6px rgba(188,140,255,0.3)', flexShrink: 0, animation: computeStats.jobsCompleted > 0 ? 'none' : 'pulse 2s infinite' }} />
            <span style={{ color: '#BC8CFF', fontFamily: mono, fontSize: 10, fontWeight: 700, letterSpacing: 0.3 }}>
              COMPUTE
            </span>
            <span style={{ color: '#8B949E', fontFamily: mono, fontSize: 10 }}>
              {computeStats.jobsCompleted > 0
                ? `${computeStats.jobsCompleted} jobs | ${(computeStats.totalCpuTimeMs / 1000).toFixed(1)}s`
                : 'idle'}
            </span>
          </div>
          <div style={divider} />
        </>
      )}

      {/* LIVE / PAPER mode */}
      <button
        className={`trading-mode-toggle ${isPaper ? 'paper' : 'live'}`}
        onClick={toggleTradingMode}
        style={{ marginRight: 0 }}
      >
        <span className="trading-mode-dot" />
        <span className="trading-mode-label">{isPaper ? 'PAPER' : 'LIVE'}</span>
      </button>
    </div>
  );
}

// ── Signal Count Badge (polls signal count for nav badge) ──────────────────
function SignalCountBadge() {
  const [count, setCount] = useState(0);
  useEffect(() => {
    let mounted = true;
    const poll = () => {
      fetch(`${getApiBase()}/signals/latest?promoted_only=true`, {
        headers: { Authorization: `Bearer ${localStorage.getItem('aura_token') || ''}` },
      })
        .then(r => r.ok ? r.json() : null)
        .then(d => { if (mounted && d?.count != null) setCount(d.count); })
        .catch(() => {});
    };
    poll();
    const iv = setInterval(poll, 30000);
    return () => { mounted = false; clearInterval(iv); };
  }, []);
  if (!count) return null;
  return (
    <span style={{
      display: 'inline-flex', alignItems: 'center', justifyContent: 'center',
      minWidth: 18, height: 18, borderRadius: 9, marginLeft: 'auto',
      background: 'rgba(96,165,250,0.2)', color: '#60A5FA',
      fontSize: 10, fontWeight: 700, padding: '0 4px',
      fontFamily: "'JetBrains Mono', monospace",
    }}>
      {count > 99 ? '99+' : count}
    </span>
  );
}

