// ── Shell Component ─────────────────────────────────────────────────────────
export default function Shell() {
  const navigate = useNavigate();
  const location = useLocation();
  const path = location.pathname;
  const isMobile = useIsMobile();
  const isNative = useIsNativeApp();
  const { theme } = useTheme();
  const ver = useVersionCheck();
  const { data: beVersion } = usePoll(
    () => fetch(`${getApiBase()}/version`).then(r => r.ok ? r.json() : null).catch(() => null),
    { intervalMs: 60_000 }
  );

  // ── Online/Offline Detection ──────────────────────────────────────────────
  const { isOnline, wasOffline } = useOnlineStatus();

  // ── Subscription Check (polls /api/billing/overview every 5 min) ──────────
  const subscription = useSubscriptionCheck();

  // ── Global Achievement Overlay (polls for achievement_unlocked notifications) ──
  const { CelebrationOverlay: GlobalAchievementOverlay } = useGlobalAchievements();

  // ── Competition Upgrade Nudges (rank, XP, streak, founding spots, rank drop) ──
  const userTier = useMemo(() => {
    try {
      const u = JSON.parse(localStorage.getItem('aura_user') || '{}');
      return u.subscription_tier || u.tier || 'explorer';
    } catch { return 'explorer'; }
  }, []);
  const { nudge: competitionNudge, dismiss: dismissCompetitionNudge } = useCompetitionUpgrades(userTier);

  // ── Auto-Share Prompts (viral growth loop) ────────────────────────────────
  const { sharePrompt, card: shareCard, dismiss: dismissShare } = useAutoShare();

  // ── ML Event Tracker (session start + page views) ──────────────────────────
  const { track } = useMLTracker();

  // Track session start once on mount
  useEffect(() => {
    track('session_start', { referrer: document.referrer || null });
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  // Prefetch all critical API data on app startup for instant page navigation
  useEffect(() => {
    prefetch.prefetchAll();
    return () => prefetch.destroy();
  }, []);

  // Track page views on route changes
  useEffect(() => {
    track('page_view', { path: location.pathname });
  }, [location.pathname]); // eslint-disable-line react-hooks/exhaustive-deps

  // Layout mode — switching mode also navigates to the corresponding primary page
  const [mode, setModeRaw] = useState(() => localStorage.getItem('aura_mode') || 'trader');
  const setMode = (m) => {
    setModeRaw(m);
    localStorage.setItem('aura_mode', m);
    // Navigate to the corresponding primary page for the active domain
    const dom = DOMAINS.find(d => d.id === activeDomain) || DOMAINS[0];
    const target = m === 'operator' ? dom.operator : dom.trader;
    navigate(target);
  };
  const toggleMode = () => setMode(mode === 'trader' ? 'operator' : 'trader');

  // Paper / Live trading mode (reactive, no page reload)
  const { mode: tradingMode, isPaper, toggle: toggleTradingMode } = useTradingMode();

  // Command palette + kill switch modal + AI drawer + chat drawer + trade celebration + shortcuts help
  const [cmdOpen, setCmdOpen] = useState(false);
  const [killOpen, setKillOpen] = useState(false);
  const [aiDrawerOpen, setAiDrawerOpen] = useState(false);
  const [chatOpen, setChatOpen] = useState(false);
  const [shortcutsOpen, setShortcutsOpen] = useState(false);
  const [celebration, setCelebration] = useState({ show: false, pnl: 0 });
  const [userMenuOpen, setUserMenuOpen] = useState(false);
  const userMenuRef = useRef(null);
  const gChordRef = useRef(null); // for G+X two-key chord navigation

  // User initial from localStorage
  const userInitial = useMemo(() => {
    try {
      const u = JSON.parse(localStorage.getItem('aura_user') || '{}');
      const name = u.display_name || u.username || '';
      return name.charAt(0).toUpperCase() || 'U';
    } catch { return 'U'; }
  }, []);

  // Close user menu on outside click
  useEffect(() => {
    if (!userMenuOpen) return;
    const handler = (e) => {
      if (userMenuRef.current && !userMenuRef.current.contains(e.target)) setUserMenuOpen(false);
    };
    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, [userMenuOpen]);

  // Determine active domain from path
  const activeDomain = useMemo(() => {
    for (const d of DOMAINS) {
      if (path === d.trader || path === d.operator || path === '/') {
        if (d.id === 'command' && (path === '/trader/command' || path === '/' || path === '/home' || path === '/operator/regime-risk')) return 'command';
        if (path === d.trader || path === d.operator) return d.id;
      }
      const subs = [...(d.traderSub || []), ...(d.operatorSub || [])];
      if (subs.some(s => path.startsWith(s.path))) return d.id;
    }
    if (TOOLS_ITEMS.some(s => path.startsWith(s.path))) return 'tools';
    if (INFRA_ITEMS.some(s => path.startsWith(s.path))) return 'infrastructure';
    if (PROFILE_ITEMS.some(s => path.startsWith(s.path))) return 'profile';
    if (path.startsWith('/operator/')) return 'command';
    if (path.startsWith('/trader/')) return 'command';
    if (path.startsWith('/v2/')) return 'command';
    return 'command';
  }, [path]);

  // Keyboard shortcuts (desktop only)
  useEffect(() => {
    if (isMobile) return;

    // G+X chord navigation map
    const G_CHORDS = {
      h: '/',
      p: '/positions',
      s: '/strategies',
      c: '/charts',
      a: '/alerts',
      n: '/signals',
    };

    const handler = (e) => {
      // Don't intercept when typing in inputs, textareas, or contenteditable
      const tag = e.target.tagName;
      const editable = e.target.isContentEditable;
      const isInput = tag === 'INPUT' || tag === 'TEXTAREA' || tag === 'SELECT' || editable;

      // Cmd/Ctrl+K — command palette (always active)
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
        e.preventDefault();
        setCmdOpen(o => !o);
        setCmdEverOpened(true);
        return;
      }

      // Cmd/Ctrl+number — domain switch (always active)
      if ((e.metaKey || e.ctrlKey) && !e.shiftKey && !e.altKey) {
        const pages = mode === 'operator'
          ? { '1': '/operator/regime-risk', '2': '/operator/execution-infra', '3': '/operator/ml-deploy' }
          : { '1': '/trader/command', '2': '/trader/execution', '3': '/trader/intelligence' };
        if (pages[e.key]) { e.preventDefault(); navigate(pages[e.key]); return; }
      }

      // Ctrl+/ — toggle shortcuts help (works even in inputs)
      if ((e.ctrlKey || e.metaKey) && e.key === '/') {
        e.preventDefault();
        setShortcutsOpen(o => !o);
        return;
      }

      // Below shortcuts only fire when NOT in an input field
      if (isInput) return;

      // ? — toggle shortcuts help
      if (e.key === '?' || (e.shiftKey && e.key === '/')) {
        e.preventDefault();
        setShortcutsOpen(o => !o);
        return;
      }

      // Number keys 1-9 — quick page navigation (no modifier)
      const NUM_PAGES = {
        '1': '/positions',
        '2': '/orders',
        '3': '/strategies',
        '4': '/signals',
        '5': '/charts',
        '6': '/scanners',
        '7': '/watchlists',
        '8': '/alerts',
        '9': '/bot-management',
      };
      if (!e.metaKey && !e.ctrlKey && !e.altKey && !e.shiftKey && NUM_PAGES[e.key]) {
        e.preventDefault();
        navigate(NUM_PAGES[e.key]);
        return;
      }

      // G+X chord: press G, then within 500ms press second key
      if (e.key === 'g' || e.key === 'G') {
        if (!e.metaKey && !e.ctrlKey && !e.altKey) {
          gChordRef.current = Date.now();
          return;
        }
      }

      // Check if this is the second key of a G chord
      if (gChordRef.current && (Date.now() - gChordRef.current) < 500) {
        const target = G_CHORDS[e.key.toLowerCase()];
        if (target) {
          e.preventDefault();
          gChordRef.current = null;
          navigate(target);
          return;
        }
      }
      gChordRef.current = null;
    };

    window.addEventListener('keydown', handler);
    return () => window.removeEventListener('keydown', handler);
  }, [navigate, mode, isMobile]);

  // Listen for kill-switch event from CommandPalette
  useEffect(() => {
    const handler = () => setKillOpen(true);
    window.addEventListener('aura:open-kill-switch', handler);
    return () => window.removeEventListener('aura:open-kill-switch', handler);
  }, []);

  // Listen for shortcuts-help event from CommandPalette
  useEffect(() => {
    const handler = () => setShortcutsOpen(true);
    window.addEventListener('aura:open-shortcuts', handler);
    return () => window.removeEventListener('aura:open-shortcuts', handler);
  }, []);

  // Listen for trade celebration events (dispatched when a profitable trade closes)
  // Usage: window.dispatchEvent(new CustomEvent('aura:trade-celebration', { detail: { pnl: 150.25 } }))
  useEffect(() => {
    const handler = (e) => {
      const pnl = e.detail?.pnl ?? 0;
      if (pnl > 0) {
        setCelebration({ show: true, pnl });
        // Auto-reset after animation completes
        setTimeout(() => setCelebration({ show: false, pnl: 0 }), 4000);
      }
    };
    window.addEventListener('aura:trade-celebration', handler);
    return () => window.removeEventListener('aura:trade-celebration', handler);
  }, []);

  // Get submenu items for active domain
  const subItems = useMemo(() => {
    if (activeDomain === 'tools') return TOOLS_ITEMS;
    if (activeDomain === 'infrastructure') return INFRA_ITEMS;
    if (activeDomain === 'profile') return PROFILE_ITEMS;
    const dom = DOMAINS.find(d => d.id === activeDomain);
    if (!dom) return [];
    return mode === 'operator' ? (dom.operatorSub || []) : (dom.traderSub || []);
  }, [activeDomain, mode]);

  // iOS native: determine which bottom tab is active
  const nativeActiveTab = useMemo(() => {
    if (!isNative) return null;
    if (path === '/' || path === '/mobile-home' || path === '/home' || path === '/trader/command') return 'command';
    if (path === '/mobile-signals' || path === '/signals' || path.startsWith('/signals')) return 'signals';
    if (path === '/mobile-research' || path.startsWith('/strategies') || path === '/marketplace' || path === '/strategy-builder') return 'research';
    if (path === '/mobile-positions' || path.startsWith('/positions') || path.startsWith('/orders') || path.startsWith('/accounts')) return 'portfolio';
    if (path === '/mobile-account' || path === '/profile' || path === '/appearance') return 'account';
    return 'command'; // fallback
  }, [isNative, path]);

  // iOS native: sub-tabs for current active tab
  const nativeSubItems = useMemo(() => {
    if (!isNative || !nativeActiveTab) return [];
    return IOS_SUBTABS[nativeActiveTab] || [];
  }, [isNative, nativeActiveTab]);

  // "More" drawer state (shared between native + mobile web)
  const [moreDrawerOpen, setMoreDrawerOpen] = useState(false);

  // Active tab detection for mobile web (must be before conditional returns for hooks rules)
  const mobileWebActiveTab = useMemo(() => {
    if (path === '/' || path === '/home' || path.startsWith('/trader/command') || path.startsWith('/operator/')) return 'home';
    if (path === '/signals' || path.startsWith('/signals')) return 'signals';
    if (path.startsWith('/strategies') || path === '/marketplace' || path === '/strategy-builder') return 'strategies';
    if (path.startsWith('/positions') || path.startsWith('/orders') || path.startsWith('/accounts')) return 'portfolio';
    return 'home';
  }, [path]);

  // ── iOS Native Layout ──────────────────────────────────────────────────────
  // Simplified: no mode toggle, no operator, no infra — just essential trading.
  if (isNative && isMobile) {
    return (
      <LayoutContext.Provider value={{ mode: 'trader', setMode: () => {}, toggleMode: () => {}, canToggle: false }}>
        <div className="m-shell native-shell">
          {/* Simplified header: just title + status pills, no mode toggle */}
          <header className="m-header">
            <div className="m-header-left">
              <span className="m-header-title">Aura Alpha</span>
            </div>
            <StatusPillsBar />
          </header>
          {nativeSubItems.length > 0 && <MobileSubTabs items={nativeSubItems} />}
          <ReconnectingBanner />
          <main className="m-workspace">
            <ErrorBoundary>
              <Suspense fallback={<LoadingFallback />}>
                <AnimatedPage key={location.pathname}>
                  <Outlet />
                </AnimatedPage>
              </Suspense>
            </ErrorBoundary>
          </main>
          <nav className="m-tabbar">
            {IOS_TABS.map(tab => (
              <Link
                key={tab.id}
                to={tab.path}
                className={`m-tab ${nativeActiveTab === tab.id ? 'active' : ''}`}
              >
                {tab.icon}
                <span>{tab.label}</span>
              </Link>
            ))}
          </nav>
        </div>
      </LayoutContext.Provider>
    );
  }

  // ── Mobile Web Tab Config ──────────────────────────────────────────────────
  // Same user-friendly tabs as iOS: Home, Signals, Strategies, Portfolio, More
  const MOBILE_WEB_TABS = [
    { id: 'home',       label: 'Home',       icon: icons.command,   path: mode === 'operator' ? '/operator/regime-risk' : '/trader/command' },
    { id: 'signals',    label: 'Signals',    icon: icons.intel,     path: '/signals' },
    { id: 'strategies', label: 'Strategies', icon: icons.tools,     path: '/strategies' },
    { id: 'portfolio',  label: 'Portfolio',  icon: icons.execution, path: '/positions' },
    { id: 'more',       label: 'More',       icon: icons.infra,     path: null },
  ];

  // "More" items for mobile web (superset of iOS — includes operator/system pages)
  const MOBILE_WEB_MORE_ITEMS = [
    { label: 'Charts',         path: '/charts',           icon: icons.command },
    { label: 'Alerts',         path: '/alerts',           icon: icons.bell },
    { label: 'Watchlists',     path: '/watchlists',       icon: icons.command },
    { label: 'Risk Controls',  path: '/risk',             icon: icons.infra },
    { label: 'Bot Management', path: '/bot-management',   icon: icons.infra },
    { label: 'ML Analytics',   path: '/ml-analytics',     icon: icons.intel },
    { label: 'Paper Trading',  path: '/paper-trading',    icon: icons.execution },
    { label: 'News',           path: '/news',             icon: icons.command },
    { label: 'Mission Control', path: '/mission-control', icon: icons.infra },
    { label: 'System Health',  path: '/system-health',    icon: icons.infra },
    { label: 'Settings',       path: '/system-settings',  icon: icons.profile },
    { label: 'Profile',        path: '/profile',          icon: icons.profile },
  ];

  // ── Mobile Layout (web, non-native) ────────────────────────────────────────
  if (isMobile) {
    return (
      <LayoutContext.Provider value={{ mode, setMode, toggleMode, canToggle: true }}>
        <div className="m-shell">
          <MobileHeader activeDomain={activeDomain} mode={mode} toggleMode={toggleMode} />
          <MobileSubTabs items={subItems} />
          <ReconnectingBanner />
          <main className="m-workspace">
            <ErrorBoundary>
              <Suspense fallback={<LoadingFallback />}>
                <AnimatedPage key={location.pathname}>
                  <Outlet />
                </AnimatedPage>
              </Suspense>
            </ErrorBoundary>
          </main>
          <nav className="m-tabbar">
            {MOBILE_WEB_TABS.map(tab => {
              if (tab.id === 'more') {
                return (
                  <button
                    key={tab.id}
                    className={`m-tab ${moreDrawerOpen ? 'active' : ''}`}
                    onClick={() => setMoreDrawerOpen(o => !o)}
                    style={{ background: 'none', border: 'none' }}
                  >
                    {tab.icon}
                    <span>{tab.label}</span>
                  </button>
                );
              }
              return (
                <Link
                  key={tab.id}
                  to={tab.path}
                  className={`m-tab ${mobileWebActiveTab === tab.id ? 'active' : ''}`}
                  onClick={() => setMoreDrawerOpen(false)}
                >
                  {tab.icon}
                  <span>{tab.label}</span>
                </Link>
              );
            })}
          </nav>
          {/* "More" drawer — slides up from bottom */}
          {moreDrawerOpen && (
            <>
              <div className="more-drawer-backdrop" onClick={() => setMoreDrawerOpen(false)} />
              <div className="more-drawer">
                <div className="more-drawer-handle" />
                {MOBILE_WEB_MORE_ITEMS.map(item => (
                  <Link
                    key={item.path}
                    to={item.path}
                    className={`more-drawer-item ${path === item.path ? 'active' : ''}`}
                    onClick={() => setMoreDrawerOpen(false)}
                  >
                    <span className="more-drawer-icon">{item.icon}</span>
                    <span>{item.label}</span>
                  </Link>
                ))}
              </div>
            </>
          )}
        </div>
      </LayoutContext.Provider>
    );
  }

  // ── Desktop Layout ────────────────────────────────────────────────────────
  return (
    <LayoutContext.Provider value={{ mode, setMode, toggleMode, canToggle: true }}>
      <div className="shell">
        <a href="#main-content" style={{
          position: 'absolute', top: -40, left: 0, background: '#58A6FF',
          color: '#fff', padding: '8px 16px', zIndex: 10000, fontSize: 13, fontWeight: 600,
          textDecoration: 'none', borderRadius: '0 0 8px 0',
          transition: 'top 0.2s',
        }} onFocus={(e) => { e.target.style.top = '0'; }}
           onBlur={(e) => { e.target.style.top = '-40px'; }}>
          Skip to main content
        </a>
        <div className="shell-ambient" />
        {/* ── TopBar ─────────────────────────────────────────── */}
        <header className="topbar">
          <div className="topbar-left">
            <div className="topbar-brand">
              <img
                src="/images/aura-alpha-header.webp"
                alt="Aura Alpha"
                className="topbar-logo-full"
                loading="eager"
                decoding="async"
                fetchPriority="high"
                style={{ filter: theme === 'day' ? 'invert(1)' : 'none' }}
                onError={(e) => { e.target.style.display = 'none'; }}
              />
            </div>
          </div>

          <div className="topbar-center">
            <LivePnLTicker />
          </div>

          <div className="topbar-right">
            <OfflineBadge isOnline={isOnline} wasOffline={wasOffline} />
            <button className="cmdk-hint" onClick={() => { setCmdOpen(true); }}>
              {icons.search}
              <span>Search</span>
              <kbd>⌘K</kbd>
            </button>
            <button className="topbar-icon-btn" title="AI Assistant" aria-label="AI Assistant" onClick={() => setAiDrawerOpen(true)}>
              <svg viewBox="0 0 24 24"><path d="M12 2a2 2 0 012 2c0 .74-.4 1.39-1 1.73V7h1a7 7 0 017 7h1a1 1 0 110 2h-1.07A7 7 0 0113 22h-2a7 7 0 01-6.93-6H3a1 1 0 110-2h1a7 7 0 017-7h1V5.73c-.6-.34-1-.99-1-1.73a2 2 0 012-2z"/></svg>
            </button>
            <button className="topbar-icon-btn" title="Chat" aria-label="Community Chat" onClick={() => setChatOpen(true)}>
              <svg viewBox="0 0 24 24"><path d="M21 15a2 2 0 01-2 2H7l-4 4V5a2 2 0 012-2h14a2 2 0 012 2z"/></svg>
            </button>
            <NotificationBell />
            <div className="topbar-avatar-wrap" ref={userMenuRef}>
              <div className="topbar-avatar" onClick={() => setUserMenuOpen(o => !o)} title="Account" role="button" aria-label="User Menu" tabIndex={0}>
                {userInitial}
              </div>
              {userMenuOpen && (
                <div className="topbar-user-menu">
                  <button className="user-menu-item" onClick={() => { setUserMenuOpen(false); navigate('/profile'); }}>
                    <svg viewBox="0 0 24 24" width="15" height="15"><circle cx="12" cy="8" r="4"/><path d="M20 21a8 8 0 10-16 0"/></svg>
                    Profile
                  </button>
                  <button className="user-menu-item" onClick={() => { setUserMenuOpen(false); navigate('/system-settings'); }}>
                    <svg viewBox="0 0 24 24" width="15" height="15"><circle cx="12" cy="12" r="3"/><path d="M19.4 15a1.65 1.65 0 00.33 1.82l.06.06a2 2 0 01-2.83 2.83l-.06-.06a1.65 1.65 0 00-1.82-.33 1.65 1.65 0 00-1 1.51V21a2 2 0 01-4 0v-.09A1.65 1.65 0 009 19.4a1.65 1.65 0 00-1.82.33l-.06.06a2 2 0 01-2.83-2.83l.06-.06A1.65 1.65 0 004.68 15a1.65 1.65 0 00-1.51-1H3a2 2 0 010-4h.09A1.65 1.65 0 004.6 9a1.65 1.65 0 00-.33-1.82l-.06-.06a2 2 0 012.83-2.83l.06.06A1.65 1.65 0 009 4.68a1.65 1.65 0 001-1.51V3a2 2 0 014 0v.09a1.65 1.65 0 001 1.51 1.65 1.65 0 001.82-.33l.06-.06a2 2 0 012.83 2.83l-.06.06A1.65 1.65 0 0019.4 9a1.65 1.65 0 001.51 1H21a2 2 0 010 4h-.09a1.65 1.65 0 00-1.51 1z"/></svg>
                    Settings
                  </button>
                  <div className="user-menu-divider" />
                  <button className="user-menu-item" onClick={() => { navigate('/download'); setUserMenuOpen(false); }}>
                    <svg viewBox="0 0 24 24" width="15" height="15"><path d="M21 15v4a2 2 0 01-2 2H5a2 2 0 01-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg>
                    Download Desktop App
                  </button>
                  <div className="user-menu-divider" />
                  <button className="user-menu-item user-menu-logout" onClick={() => {
                    setUserMenuOpen(false);
                    localStorage.removeItem('aura_token');
                    localStorage.removeItem('aura_user');
                    localStorage.removeItem('aura_demo');
                    navigate('/login', { replace: true });
                  }}>
                    <svg viewBox="0 0 24 24" width="15" height="15"><path d="M9 21H5a2 2 0 01-2-2V5a2 2 0 012-2h4"/><polyline points="16 17 21 12 16 7"/><line x1="21" y1="12" x2="9" y2="12"/></svg>
                    Log Out
                  </button>
                </div>
              )}
            </div>
          </div>
        </header>

        {/* ── Reconnecting Banner ─────────────────────────────── */}
        <ReconnectingBanner />

        {/* ── Subscription Expired Banner ─────────────────────── */}
        <SubscriptionBanner
          expired={subscription.expired}
          tier={subscription.tier}
          onUpgrade={() => navigate('/billing')}
        />

        {/* ── Body ───────────────────────────────────────────── */}
        <div className="shell-body">
          {/* ── SideRail ───────────────────────────────────── */}
          <aside className="siderail" aria-label="Sidebar">
            <nav className="siderail-nav" role="navigation" aria-label="Main navigation">
              {/* Section: Trading */}
              <div className="nav-section-label">Trading</div>
              <div className="domain-section">
                {DOMAINS.map(d => {
                  const target = mode === 'operator' ? d.operator : d.trader;
                  const isActive = activeDomain === d.id;
                  return (
                    <React.Fragment key={d.id}>
                      <button
                        className={`domain-tab ${isActive ? 'active' : ''}`}
                        onClick={() => navigate(target)}
                        role="menuitem"
                        aria-label={d.label}
                        aria-current={isActive ? 'page' : undefined}
                        aria-expanded={isActive && subItems.length > 0 && activeDomain === d.id ? true : undefined}
                      >
                        {d.icon}
                        {d.label}
                      </button>
                      {isActive && subItems.length > 0 && activeDomain === d.id && (
                        <div className="submenu" role="menu" aria-label={`${d.label} submenu`}>
                          {(mode === 'operator' ? (d.operatorSub || []) : (d.traderSub || [])).map(s => (
                            <NavLink
                              key={s.path}
                              to={s.path}
                              role="menuitem"
                              className={({ isActive: a }) => `submenu-item ${a ? 'active' : ''}`}
                            >
                              {s.label}
                              {s.badge && <SignalCountBadge />}
                              {PATH_SHORTCUTS[s.path] && <span className="shortcut-hint">{PATH_SHORTCUTS[s.path]}</span>}
                            </NavLink>
                          ))}
                        </div>
                      )}
                    </React.Fragment>
                  );
                })}
              </div>

              <div className="nav-divider" />

              {/* Section: Tools (hidden when empty — use Cmd+K to access) */}
              {TOOLS_ITEMS.length > 0 && (<>
              <div className="nav-section-label">Tools</div>
              <div className="domain-section">
                <button
                  className={`domain-tab ${activeDomain === 'tools' ? 'active' : ''}`}
                  onClick={() => navigate(TOOLS_ITEMS[0].path)}
                  role="menuitem"
                  aria-label="Tools"
                  aria-expanded={activeDomain === 'tools' ? true : undefined}
                >
                  {icons.tools}
                  Tools
                </button>
                {activeDomain === 'tools' && (
                  <div className="submenu" role="menu" aria-label="Tools submenu">
                    {TOOLS_ITEMS.map(s => (
                      <NavLink
                        key={s.path}
                        to={s.path}
                        role="menuitem"
                        className={({ isActive: a }) => `submenu-item ${a ? 'active' : ''}`}
                      >
                        {s.label}
                      </NavLink>
                    ))}
                  </div>
                )}
              </div>
              <div className="nav-divider" />
              </>)}

              {/* Section: System */}
              <div className="nav-section-label">System</div>
              <div className="domain-section">
                <button
                  className={`domain-tab ${activeDomain === 'infrastructure' ? 'active' : ''}`}
                  onClick={() => navigate(INFRA_ITEMS[0].path)}
                  role="menuitem"
                  aria-label="Infrastructure"
                  aria-expanded={activeDomain === 'infrastructure' ? true : undefined}
                >
                  {icons.infra}
                  Infrastructure
                </button>
                {activeDomain === 'infrastructure' && (
                  <div className="submenu" role="menu" aria-label="Infrastructure submenu">
                    {INFRA_ITEMS.map(s => (
                      <NavLink
                        key={s.path}
                        to={s.path}
                        role="menuitem"
                        className={({ isActive: a }) => `submenu-item ${a ? 'active' : ''}`}
                      >
                        {s.label}
                      </NavLink>
                    ))}
                  </div>
                )}
              </div>

              <div className="nav-divider" />

              {/* Section: Account */}
              <div className="nav-section-label">Account</div>
              <div className="domain-section">
                <button
                  className={`domain-tab ${activeDomain === 'profile' ? 'active' : ''}`}
                  onClick={() => navigate(PROFILE_ITEMS[0].path)}
                  role="menuitem"
                  aria-label="Profile"
                  aria-expanded={activeDomain === 'profile' ? true : undefined}
                >
                  {icons.profile}
                  Profile
                </button>
                {activeDomain === 'profile' && (
                  <div className="submenu" role="menu" aria-label="Profile submenu">
                    {PROFILE_ITEMS.map(s => (
                      <NavLink
                        key={s.path}
                        to={s.path}
                        role="menuitem"
                        className={({ isActive: a }) => `submenu-item ${a ? 'active' : ''}`}
                      >
                        {s.label}
                      </NavLink>
                    ))}
                  </div>
                )}
              </div>
            </nav>

            {/* Globe */}
            <div className="siderail-footer">
              <span className="globe-label">Global Markets</span>
              <GlobeWidget />
            </div>

            {/* Version footer */}
            <div className="version-footer">
              <span>FE v{ver.currentVersion} ({ver.currentHash})</span>
              {beVersion && <span>BE v{beVersion.version || '?'} ({beVersion.commit || '?'})</span>}
            </div>
          </aside>

          {/* ── Workspace ──────────────────────────────────── */}
          <main id="main-content" className={`workspace${isPaper ? ' workspace--paper' : ''}`}>
            {/* Breadcrumb navigation */}
            <Breadcrumbs />
            {/* Paper mode environment banner */}
            {isPaper && (
              <div className="paper-mode-banner">
                <svg viewBox="0 0 24 24" width="14" height="14" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                  <path d="M12 9v2m0 4h.01M10.29 3.86L1.82 18a2 2 0 001.71 3h16.94a2 2 0 001.71-3L13.71 3.86a2 2 0 00-3.42 0z"/>
                </svg>
                <span>PAPER TRADING MODE</span>
                <span className="paper-mode-banner-sub">Simulated data &mdash; no real orders executed</span>
                <button className="paper-mode-banner-exit" onClick={toggleTradingMode}>Switch to Live</button>
              </div>
            )}
            {ver.updateAvailable && (
              <div className="update-banner">
                <span>New version available (v{ver.remoteVersion})</span>
                <button className="update-banner-btn" onClick={ver.refresh}>Refresh Now</button>
                <button className="update-banner-dismiss" onClick={ver.dismiss}>&times;</button>
              </div>
            )}
            <ErrorBoundary>
              <Suspense fallback={<LoadingFallback />}>
                <AnimatedPage key={location.pathname}>
                  <Outlet />
                </AnimatedPage>
              </Suspense>
            </ErrorBoundary>
          </main>
        </div>

        {/* ── Global Status Bar ──────────────────────────────── */}
        <GlobalStatusBar isPaper={isPaper} toggleTradingMode={toggleTradingMode} />

      </div>

      {/* Lazy-loaded modals/drawers — chunks fetched on first open, not at Shell mount */}
      <Suspense fallback={null}>
        {/* Command Palette (Cmd+K / Ctrl+K) — has internal AnimatePresence for exit */}
        <CommandPalette open={cmdOpen} onClose={() => setCmdOpen(false)} />
        {/* Kill Switch Modal */}
        {killOpen && <KillSwitchModal isOpen={killOpen} onClose={() => setKillOpen(false)} />}
        {/* AI Assistant Drawer */}
        <AIAssistantDrawer open={aiDrawerOpen} onClose={() => setAiDrawerOpen(false)} />
        {/* Community Chat Drawer */}
        {chatOpen && <ChatRoom open={chatOpen} onClose={() => setChatOpen(false)} />}
        {/* Keyboard Shortcuts Help (? key) */}
        <KeyboardShortcutsHelp open={shortcutsOpen} onClose={() => setShortcutsOpen(false)} />
        {/* Trade Celebration Overlay — triggered via window event */}
        {celebration.show && <TradeCelebration show={celebration.show} pnl={celebration.pnl} />}
        {/* Global Achievement Celebration Overlay — triggered by competition notifications */}
        {GlobalAchievementOverlay}
        {/* Competition Upgrade Modal — rank, XP, streak, founding spots, rank drop */}
        {competitionNudge && <CompetitionUpgradeModal nudge={competitionNudge} onDismiss={dismissCompetitionNudge} />}
        {/* Auto-Share Performance Card — viral growth loop */}
        {sharePrompt && shareCard && <ShareCard card={shareCard} onClose={dismissShare} />}
        {/* PWA Install Prompt — "Add to Home Screen" for mobile browsers */}
        <PWAInstallPrompt />
      </Suspense>
      {/* Floating "?" button — bottom-right corner */}
      <button
        onClick={() => setShortcutsOpen(true)}
        title="Keyboard Shortcuts (?)"
        aria-label="Keyboard Shortcuts"
        style={{
          position: 'fixed', bottom: 52, right: 20, zIndex: 900,
          width: 32, height: 32, borderRadius: '50%',
          background: 'rgba(255,255,255,0.06)',
          border: '1px solid rgba(255,255,255,0.1)',
          color: 'rgba(255,255,255,0.4)',
          fontSize: 14, fontWeight: 700,
          fontFamily: "'JetBrains Mono', monospace",
          cursor: 'pointer', display: 'flex',
          alignItems: 'center', justifyContent: 'center',
          transition: 'all 0.15s ease',
          backdropFilter: 'blur(8px)',
        }}
        onMouseEnter={(e) => {
          e.currentTarget.style.background = 'rgba(96,165,250,0.15)';
          e.currentTarget.style.borderColor = 'rgba(96,165,250,0.3)';
          e.currentTarget.style.color = '#60A5FA';
        }}
        onMouseLeave={(e) => {
          e.currentTarget.style.background = 'rgba(255,255,255,0.06)';
          e.currentTarget.style.borderColor = 'rgba(255,255,255,0.1)';
          e.currentTarget.style.color = 'rgba(255,255,255,0.4)';
        }}
      >
        ?
      </button>
    </LayoutContext.Provider>
  );
}

export { LoadingFallback };
