import { useState, useEffect, useCallback } from 'react';
import { api } from '../utils/api';

const SHARE_COOLDOWN = 24 * 60 * 60 * 1000;

function shouldPrompt(key) {
  const ts = localStorage.getItem(`aura_share_${key}`);
  return !ts || Date.now() - parseInt(ts) > SHARE_COOLDOWN;
}

function markPrompted(key) {
  localStorage.setItem(`aura_share_${key}`, Date.now().toString());
}

export function useAutoShare() {
  const [sharePrompt, setSharePrompt] = useState(null);
  const [card, setCard] = useState(null);

  const checkTriggers = useCallback(async () => {
    try {
      const [rankData, profile] = await Promise.all([
        api('/rankings/me', { silent: true }).catch(() => null),
        api('/gamification/profile', { silent: true }).catch(() => null),
      ]);

      // Trigger: entered top 10%
      if (rankData?.percentile >= 90 && shouldPrompt('top10')) {
        markPrompted('top10');
        const c = await api('/growth/card', { silent: true });
        setCard(c);
        setSharePrompt({ type: 'top_percentile', message: `You're in the top ${rankData.percentile.toFixed(0)}%! Share your performance.` });
        return;
      }

      // Trigger: 7+ day streak
      if (profile?.streak_days >= 7 && profile.streak_days % 7 === 0 && shouldPrompt(`streak_${profile.streak_days}`)) {
        markPrompted(`streak_${profile.streak_days}`);
        const c = await api('/growth/card', { silent: true });
        setCard(c);
        setSharePrompt({ type: 'streak', message: `${profile.streak_days}-day streak! Show off your consistency.` });
        return;
      }

      // Trigger: rank improved by 5+
      if (rankData?.delta >= 5 && shouldPrompt('rank_up')) {
        markPrompted('rank_up');
        const c = await api('/growth/card', { silent: true });
        setCard(c);
        setSharePrompt({ type: 'rank_up', message: `You climbed ${rankData.delta} spots! Share your progress.` });
        return;
      }

    } catch {}
  }, []);

  useEffect(() => {
    const timeout = setTimeout(checkTriggers, 10000); // Check 10s after mount
    return () => clearTimeout(timeout);
  }, [checkTriggers]);

  const dismiss = () => { setSharePrompt(null); setCard(null); };

  return { sharePrompt, card, dismiss };
}
