import { createContext, useContext, useEffect, useMemo, useReducer } from "react";

const LS_KEY = "aura_v2_store_v1";

const initial = {
  role: "operator",
  density: "comfortable",
  accessibility: "standard",
  offlineMode: false,
  linked: { strategy: "", symbol: "", bot: "" },
  layoutProfiles: {
    active: "Default",
    profiles: {
      Default: {
        dashboardWidgets: ["equity", "bench", "regime", "approvals", "execution", "risk", "telemetry", "incidents"],
      },
    },
  },
  commandPaletteOpen: false,
  toast: null,
};

function load() {
  try {
    const raw = localStorage.getItem(LS_KEY);
    if (!raw) return null;
    const parsed = JSON.parse(raw);
    return parsed && typeof parsed === "object" ? parsed : null;
  } catch {
    return null;
  }
}

function save(state) {
  try {
    localStorage.setItem(LS_KEY, JSON.stringify(state));
  } catch {}
}

function reducer(state, action) {
  switch (action.type) {
    case "SET_ROLE":
      return { ...state, role: action.role };
    case "SET_DENSITY":
      return { ...state, density: action.density };
    case "SET_ACCESSIBILITY":
      return { ...state, accessibility: action.accessibility };
    case "SET_OFFLINE":
      return { ...state, offlineMode: !!action.offlineMode };
    case "SET_LINKED":
      return { ...state, linked: { ...state.linked, ...action.payload } };
    case "OPEN_PALETTE":
      return { ...state, commandPaletteOpen: true };
    case "CLOSE_PALETTE":
      return { ...state, commandPaletteOpen: false };
    case "TOAST":
      return { ...state, toast: action.toast };
    case "CLEAR_TOAST":
      return { ...state, toast: null };
    case "SET_ACTIVE_PROFILE":
      return { ...state, layoutProfiles: { ...state.layoutProfiles, active: action.name } };
    case "UPSERT_PROFILE": {
      const { name, profile } = action;
      return {
        ...state,
        layoutProfiles: {
          ...state.layoutProfiles,
          profiles: { ...state.layoutProfiles.profiles, [name]: profile },
        },
      };
    }
    default:
      return state;
  }
}

const Ctx = createContext(null);

export function AppStoreProvider({ children }) {
  const loaded = typeof window !== "undefined" ? load() : null;
  const [state, dispatch] = useReducer(reducer, loaded ? { ...initial, ...loaded } : initial);

  useEffect(() => { save(state); }, [state]);

  const api = useMemo(() => ({
    state,
    dispatch,
    setRole: (role) => dispatch({ type: "SET_ROLE", role }),
    setDensity: (density) => dispatch({ type: "SET_DENSITY", density }),
    setAccessibility: (accessibility) => dispatch({ type: "SET_ACCESSIBILITY", accessibility }),
    setOfflineMode: (offlineMode) => dispatch({ type: "SET_OFFLINE", offlineMode }),
    setLinked: (payload) => dispatch({ type: "SET_LINKED", payload }),
    openPalette: () => dispatch({ type: "OPEN_PALETTE" }),
    closePalette: () => dispatch({ type: "CLOSE_PALETTE" }),
    toast: (text, tone = "info") => dispatch({ type: "TOAST", toast: { text, tone, ts: Date.now() } }),
    clearToast: () => dispatch({ type: "CLEAR_TOAST" }),
    setActiveProfile: (name) => dispatch({ type: "SET_ACTIVE_PROFILE", name }),
    upsertProfile: (name, profile) => dispatch({ type: "UPSERT_PROFILE", name, profile }),
  }), [state]);

  return <Ctx.Provider value={api}>{children}</Ctx.Provider>;
}

export function useAppStore() {
  const v = useContext(Ctx);
  if (!v) throw new Error("useAppStore must be used inside AppStoreProvider");
  return v;
}
