import { Component, useState } from 'react';

/**
 * Section-level Error Boundary for Aura Alpha.
 *
 * Unlike the top-level ErrorBoundary (src/components/ErrorBoundary.jsx) which
 * catches app-wide crashes and handles chunk load errors, this component is
 * designed to wrap individual pages or sections so a crash in one area doesn't
 * take down the whole app.
 *
 * Props:
 *   name       - Display name for the crashed component (e.g. "Dashboard")
 *   fallback   - Optional custom fallback element (overrides default UI)
 *   onReset    - Optional callback when user clicks "Try Again"
 *   children   - Content to render
 */

interface SectionErrorBoundaryProps {
  children: React.ReactNode
  name?: string
  fallback?: React.ReactNode
  onReset?: () => void
}

interface SectionErrorBoundaryState {
  hasError: boolean
  error: Error | null
  componentStack: string | null
}

class SectionErrorBoundary extends Component<SectionErrorBoundaryProps, SectionErrorBoundaryState> {
  constructor(props: SectionErrorBoundaryProps) {
    super(props);
    this.state = { hasError: false, error: null, componentStack: null };
  }

  static getDerivedStateFromError(error: Error): Partial<SectionErrorBoundaryState> {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, info: React.ErrorInfo) {
    const name = this.props.name || 'Component';
    console.error(`[ErrorBoundary:${name}]`, error, info);
    if (info?.componentStack) {
      this.setState({ componentStack: info.componentStack });
    }
  }

  handleReset = () => {
    this.props.onReset?.();
    this.setState({ hasError: false, error: null, componentStack: null });
  };

  render() {
    if (this.state.hasError) {
      if (this.props.fallback) return this.props.fallback;
      return (
        <ErrorFallbackUI
          name={this.props.name}
          error={this.state.error}
          componentStack={this.state.componentStack}
          onReset={this.handleReset}
        />
      );
    }
    return this.props.children;
  }
}

/* ── Functional fallback (useState for collapsible details) ──────────────── */
interface ErrorFallbackUIProps {
  name?: string
  error: Error | null
  componentStack: string | null
  onReset: () => void
}

function ErrorFallbackUI({ name, error, componentStack, onReset }: ErrorFallbackUIProps) {
  const [showDetails, setShowDetails] = useState(false);

  const errorText = error?.message || error?.toString() || 'Unknown error';
  const stackText = error?.stack || '';
  const label = name || 'This section';

  return (
    <div style={{
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      minHeight: 280,
      backgroundColor: '#0D1117',
      fontFamily: "'Plus Jakarta Sans', system-ui, sans-serif",
      padding: 24,
    }}>
      <div style={{
        textAlign: 'center',
        maxWidth: 440,
        width: '100%',
        padding: 32,
        borderRadius: 14,
        backgroundColor: '#161B22',
        border: '1px solid #30363D',
        boxShadow: '0 4px 24px rgba(0, 0, 0, 0.3)',
      }}>
        {/* Error icon */}
        <div style={{
          width: 48,
          height: 48,
          borderRadius: '50%',
          background: 'linear-gradient(135deg, rgba(248,81,73,0.12), rgba(210,153,34,0.12))',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          margin: '0 auto 16px',
        }}>
          <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="#F85149" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <circle cx="12" cy="12" r="10" />
            <line x1="12" y1="8" x2="12" y2="12" />
            <line x1="12" y1="16" x2="12.01" y2="16" />
          </svg>
        </div>

        {/* Title */}
        <h3 style={{
          color: '#E6EDF3',
          fontSize: 17,
          fontWeight: 600,
          margin: '0 0 6px 0',
          letterSpacing: '-0.01em',
        }}>
          {label} crashed
        </h3>

        {/* Description */}
        <p style={{
          color: '#8B949E',
          fontSize: 13,
          margin: '0 0 20px 0',
          lineHeight: 1.5,
        }}>
          An unexpected error occurred. The rest of the app is still working.
        </p>

        {/* Action buttons */}
        <div style={{ display: 'flex', gap: 10, justifyContent: 'center', flexWrap: 'wrap', marginBottom: 16 }}>
          <button
            onClick={onReset}
            style={{
              padding: '9px 22px',
              borderRadius: 10,
              border: 'none',
              background: 'linear-gradient(135deg, #60A5FA, #A78BFA)',
              color: '#ffffff',
              fontSize: 13,
              fontWeight: 600,
              cursor: 'pointer',
              fontFamily: "'Plus Jakarta Sans', system-ui, sans-serif",
              boxShadow: '0 4px 16px rgba(96, 165, 250, 0.25)',
              transition: 'opacity 0.15s',
            }}
            onMouseEnter={e => e.currentTarget.style.opacity = '0.85'}
            onMouseLeave={e => e.currentTarget.style.opacity = '1'}
          >
            Try Again
          </button>
          <button
            onClick={() => window.location.reload()}
            style={{
              padding: '9px 22px',
              borderRadius: 10,
              border: '1px solid #30363D',
              background: 'transparent',
              color: '#8B949E',
              fontSize: 13,
              fontWeight: 600,
              cursor: 'pointer',
              fontFamily: "'Plus Jakarta Sans', system-ui, sans-serif",
              transition: 'border-color 0.15s, color 0.15s',
            }}
            onMouseEnter={e => { e.currentTarget.style.borderColor = '#8B949E'; e.currentTarget.style.color = '#E6EDF3'; }}
            onMouseLeave={e => { e.currentTarget.style.borderColor = '#30363D'; e.currentTarget.style.color = '#8B949E'; }}
          >
            Reload Page
          </button>
        </div>

        {/* Collapsible error details */}
        <div style={{ textAlign: 'left' }}>
          <button
            onClick={() => setShowDetails(!showDetails)}
            style={{
              background: 'none',
              border: 'none',
              color: '#484F58',
              fontSize: 11,
              cursor: 'pointer',
              padding: '4px 0',
              fontFamily: "'Plus Jakarta Sans', system-ui, sans-serif",
              display: 'flex',
              alignItems: 'center',
              gap: 6,
              transition: 'color 0.15s',
            }}
            onMouseEnter={e => e.currentTarget.style.color = '#8B949E'}
            onMouseLeave={e => e.currentTarget.style.color = '#484F58'}
          >
            <svg
              width="11"
              height="11"
              viewBox="0 0 24 24"
              fill="none"
              stroke="currentColor"
              strokeWidth="2"
              strokeLinecap="round"
              strokeLinejoin="round"
              style={{
                transform: showDetails ? 'rotate(90deg)' : 'rotate(0deg)',
                transition: 'transform 0.2s',
              }}
            >
              <polyline points="9 18 15 12 9 6" />
            </svg>
            Technical details
          </button>
          {showDetails && (
            <div style={{
              marginTop: 6,
              padding: 12,
              borderRadius: 8,
              backgroundColor: '#0D1117',
              border: '1px solid #21262D',
              maxHeight: 160,
              overflow: 'auto',
            }}>
              <div style={{
                fontFamily: "'JetBrains Mono', 'Fira Code', monospace",
                fontSize: 10,
                lineHeight: 1.5,
                color: '#F85149',
                wordBreak: 'break-word',
                whiteSpace: 'pre-wrap',
                marginBottom: stackText || componentStack ? 6 : 0,
              }}>
                {errorText}
              </div>
              {componentStack && (
                <div style={{
                  fontFamily: "'JetBrains Mono', 'Fira Code', monospace",
                  fontSize: 9,
                  lineHeight: 1.4,
                  color: '#484F58',
                  wordBreak: 'break-word',
                  whiteSpace: 'pre-wrap',
                  borderTop: '1px solid #21262D',
                  paddingTop: 6,
                  marginTop: 6,
                }}>
                  Component stack:{componentStack}
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

export default SectionErrorBoundary;
