/* =============================================================================
   useCelebration — Hook for triggering celebration overlays

   Usage:
     const { celebrate, CelebrationOverlay } = useCelebration();

     celebrate({ title: 'First Trade', description: '...', tier: 'common' });

     return <>{CelebrationOverlay}</>; // render in JSX
   ============================================================================= */
import { useState, useCallback, useRef } from 'react';
import { createElement } from 'react';
import Celebration from '../components/Celebration';

/**
 * @returns {{ celebrate: Function, CelebrationOverlay: React.ReactElement }}
 */
export default function useCelebration() {
  const [queue, setQueue] = useState([]);
  const [current, setCurrent] = useState(null);
  const processingRef = useRef(false);

  // Process the next item in queue
  const processNext = useCallback(() => {
    setQueue(prev => {
      if (prev.length === 0) {
        processingRef.current = false;
        setCurrent(null);
        return prev;
      }
      const [next, ...rest] = prev;
      setCurrent(next);
      return rest;
    });
  }, []);

  /**
   * Trigger a celebration.
   * @param {{ title: string, description?: string, tier?: string, icon?: string }} opts
   */
  const celebrate = useCallback((opts) => {
    const item = {
      id: Date.now() + Math.random(),
      title: opts.title || 'Achievement Unlocked',
      description: opts.description || '',
      tier: opts.tier || 'common',
      icon: opts.icon || null,
      autoDismissMs: opts.autoDismissMs || 4000,
    };

    if (!processingRef.current) {
      // Nothing playing — start immediately
      processingRef.current = true;
      setCurrent(item);
    } else {
      // Queue it
      setQueue(prev => [...prev, item]);
    }
  }, []);

  const handleDismiss = useCallback(() => {
    // Small gap before next celebration
    setTimeout(() => processNext(), 200);
  }, [processNext]);

  /**
   * Check for newly earned achievements (compare against localStorage).
   * Returns array of new achievement objects.
   * @param {Array} achievements - full list with { id, name, description, tier, icon, earned }
   * @param {string} storageKey - localStorage key for tracking seen achievements
   */
  const checkNewAchievements = useCallback((achievements, storageKey = 'aura_achievements_seen') => {
    if (!Array.isArray(achievements)) return [];

    const earned = achievements.filter(a => a.earned);
    const prevSeen = JSON.parse(localStorage.getItem(storageKey) || '[]');
    const prevSet = new Set(prevSeen);

    const newOnes = earned.filter(a => !prevSet.has(a.id));

    if (newOnes.length > 0) {
      // Update seen list
      const allEarnedIds = earned.map(a => a.id);
      localStorage.setItem(storageKey, JSON.stringify(allEarnedIds));
    }

    return newOnes;
  }, []);

  /**
   * Trigger celebrations for an array of achievements.
   * @param {Array} achievements - [{ name, description, tier, icon }]
   */
  const celebrateAchievements = useCallback((achievements) => {
    if (!Array.isArray(achievements)) return;
    achievements.forEach((a, i) => {
      // Stagger slightly so queue processes in order
      setTimeout(() => {
        celebrate({
          title: a.name || a.title || 'Achievement Unlocked',
          description: a.description || '',
          tier: a.tier || 'common',
          icon: a.icon || null,
        });
      }, i * 100);
    });
  }, [celebrate]);

  // The overlay element to render
  const CelebrationOverlay = current
    ? createElement(Celebration, {
        key: current.id,
        visible: true,
        title: current.title,
        description: current.description,
        tier: current.tier,
        icon: current.icon,
        autoDismissMs: current.autoDismissMs,
        onDismiss: handleDismiss,
      })
    : null;

  return {
    celebrate,
    celebrateAchievements,
    checkNewAchievements,
    CelebrationOverlay,
  };
}
