/* ═══════════════════════════════════════════════════════════════════════════
   useTradingMode — Centralized Paper/Live trading mode state
   Persists in localStorage, broadcasts changes via custom event so all
   components react without a full page reload.
   ═══════════════════════════════════════════════════════════════════════════ */
import { useState, useEffect, useCallback, useMemo } from 'react';

const STORAGE_KEY = 'aura_trading_mode';
const EVENT_NAME = 'trading-mode-change';

// Paper mode simulated portfolio data
const PAPER_PORTFOLIO = {
  equity: 10000,
  dayPnl: 127.43,
  weekPnl: 342.18,
  monthPnl: 891.50,
  buyingPower: 39500,
  exposure: 10500,
  heat: 22,
  positions: [
    { symbol: 'AAPL', qty: 15, avg: 178.50, last: 182.30, pnl: 57.00, side: 'LONG' },
    { symbol: 'MSFT', qty: 10, avg: 415.20, last: 418.90, pnl: 37.00, side: 'LONG' },
    { symbol: 'NVDA', qty: 5,  avg: 875.00, last: 881.60, pnl: 33.00, side: 'LONG' },
    { symbol: 'TSLA', qty: -3, avg: 248.00, last: 245.80, pnl: 6.60,  side: 'SHORT' },
  ],
  bots: [
    {
      name: 'Paper-Alpha', mode: 'paper', status: 'OK', connected: true,
      equity: 5200, pnl: { day: 72.10, week: 189.00, month: 480.00 },
      positions: 3, trades: 47, buyingPower: 20000,
      equityCurve: Array.from({ length: 30 }, (_, i) => ({
        ts: Math.floor(Date.now() / 1000) - (30 - i) * 86400,
        value: 5000 + Math.sin(i * 0.3) * 100 + i * 8,
      })),
    },
    {
      name: 'Paper-Crypto', mode: 'paper', status: 'OK', connected: true,
      equity: 4800, pnl: { day: 55.33, week: 153.18, month: 411.50 },
      positions: 1, trades: 31, buyingPower: 19500,
      equityCurve: Array.from({ length: 30 }, (_, i) => ({
        ts: Math.floor(Date.now() / 1000) - (30 - i) * 86400,
        value: 4700 + Math.cos(i * 0.25) * 80 + i * 5,
      })),
    },
  ],
  orders: [
    { symbol: 'AAPL', side: 'BUY', qty: 5, type: 'LIMIT', price: 179.00, status: 'Working', time: new Date().toISOString() },
    { symbol: 'GOOGL', side: 'BUY', qty: 3, type: 'LIMIT', price: 155.00, status: 'Working', time: new Date().toISOString() },
  ],
};

export function useTradingMode() {
  const [mode, setModeRaw] = useState(() => localStorage.getItem(STORAGE_KEY) || 'live');

  // Listen for changes from other components / tabs
  useEffect(() => {
    const handler = () => {
      setModeRaw(localStorage.getItem(STORAGE_KEY) || 'live');
    };
    window.addEventListener(EVENT_NAME, handler);
    window.addEventListener('storage', (e) => {
      if (e.key === STORAGE_KEY) handler();
    });
    return () => {
      window.removeEventListener(EVENT_NAME, handler);
      window.removeEventListener('storage', handler);
    };
  }, []);

  const isPaper = mode === 'paper';

  const setMode = useCallback((newMode) => {
    const m = newMode === 'paper' ? 'paper' : 'live';
    localStorage.setItem(STORAGE_KEY, m);
    setModeRaw(m);
    window.dispatchEvent(new Event(EVENT_NAME));
  }, []);

  const toggle = useCallback(() => {
    setMode(mode === 'live' ? 'paper' : 'live');
  }, [mode, setMode]);

  // Paper portfolio data (only returned when in paper mode)
  const paperData = useMemo(() => isPaper ? PAPER_PORTFOLIO : null, [isPaper]);

  return { mode, isPaper, setMode, toggle, paperData };
}

export default useTradingMode;
