/**
 * AURA ALPHA -- Platform Branching Configuration
 *
 * Aura Alpha is desktop-first. iOS (Capacitor) gets ~10 essential pages;
 * web/desktop gets the full 87+ page experience.
 *
 * Usage:
 *   import { isIOS, isPageAvailable } from '@/config/platform';
 *   if (!isPageAvailable('/ml-analytics')) redirect('/');
 */

// ── Platform detection ──────────────────────────────────────────────────────

function detectIOS() {
  try {
    const cap = window.Capacitor;
    if (!cap?.isNativePlatform?.()) return false;
    // Capacitor exposes getPlatform() — 'ios' | 'android' | 'web'
    const platform = cap.getPlatform?.() || '';
    return platform === 'ios';
  } catch {
    return false;
  }
}

function detectNative() {
  try {
    return window.Capacitor?.isNativePlatform?.() || false;
  } catch {
    return false;
  }
}

/** true when running inside Capacitor on iOS */
export const isIOS = detectIOS();

/** true when running inside any Capacitor native shell (iOS or Android) */
export const isNative = detectNative();

// ── iOS-available route paths ───────────────────────────────────────────────
// These are the ~10 essential page groups available on iOS.
// Each entry is a route path prefix — sub-routes (e.g. /positions/:symbol)
// are matched by startsWith logic in isPageAvailable().

export const iOSPages = [
  // Auth
  '/login',
  '/register',
  '/forgot-password',

  // Mobile native app routes (standalone pages with own tab bar)
  '/mobile-home',
  '/mobile-positions',
  '/mobile-signals',
  '/mobile-research',
  '/mobile-account',

  // Main dashboard
  '/',
  '/home',
  '/trader/command',

  // Positions
  '/positions',

  // Orders
  '/orders',

  // Alerts
  '/alerts',

  // Strategy catalogue
  '/strategies',

  // Charts
  '/charts',

  // Gateway / connection status
  '/gateway',
  '/system-health',

  // Notifications
  '/notifications',

  // Signals (desktop version, also accessible)
  '/signals',

  // Profile & Settings
  '/profile',
  '/appearance',

  // Portfolio
  '/portfolio',
  '/portfolio-brain',

  // Public / legal pages (always available)
  '/landing',
  '/onboarding',
  '/features',
  '/showcase',
  '/public-pricing',
  '/docs',
  '/about',
  '/terms',
  '/privacy',
  '/risk-disclosure',
  '/cookies',
  '/alpha-agreement',
  '/shared',

  // Download / app pages
  '/apps',
  '/download',
  '/install',
  '/desktop',
  '/mobile',
];

// ── Helper ──────────────────────────────────────────────────────────────────

/**
 * Check whether a given route path is available on the current platform.
 * On web/desktop every page is available. On iOS only iOSPages are allowed.
 *
 * @param {string} routePath - The route path to check (e.g. '/ml-analytics')
 * @returns {boolean}
 */
export function isPageAvailable(routePath) {
  // Web/desktop: everything is available
  if (!isIOS) return true;

  // Normalize
  const path = (routePath || '/').replace(/\/+$/, '') || '/';

  // Exact match on index route
  if (path === '/') return true;

  // Check if the path matches or is a child of any iOS-allowed route
  return iOSPages.some((allowed) => {
    if (allowed === '/') return path === '/';
    return path === allowed || path.startsWith(allowed + '/');
  });
}
