// ── Root gate: Landing for visitors, dashboard for logged-in users ────────
const IS_TAURI = typeof window !== 'undefined' && !!window.__TAURI_INTERNALS__;

function RootGate() {
  const token = typeof window !== 'undefined' ? localStorage.getItem('aura_token') : null;
  // Native app: always go to mobile home (auth handled inside the page)
  if (IS_NATIVE) return <Navigate to="/mobile-home" replace />;
  // Desktop app (Tauri): standalone mode — go straight to dashboard
  // No login required for paper trading / backtesting
  if (IS_TAURI && !token) return <Navigate to="/home" replace />;
  if (!token) return <LandingPage />;
  return <Navigate to="/home" replace />;
}

