import React from 'react';
import ReactDOM from 'react-dom/client';
import { BrowserRouter } from 'react-router-dom';
import { Capacitor } from '@capacitor/core';
import './i18n';
import App from './App';
import { initNative } from './utils/nativeBootstrap';
import { hydrateFromNative } from './utils/storage';

// Sentry error monitoring — deferred until after page is fully loaded + 3s
// so the 458KB chunk never competes with initial paint or interactivity
const sentryDsn = import.meta.env.VITE_SENTRY_DSN || '';
if (sentryDsn) {
  const initSentry = () => {
    setTimeout(() => {
      import('@sentry/react').then(Sentry => {
        Sentry.init({
          dsn: sentryDsn,
          environment: import.meta.env.MODE || 'production',
          release: typeof __APP_VERSION__ !== 'undefined' && typeof __BUILD_HASH__ !== 'undefined'
            ? `aura-alpha@${__APP_VERSION__}+${__BUILD_HASH__}`
            : undefined,
          tracesSampleRate: 0.1,
          replaysSessionSampleRate: 0,
          replaysOnErrorSampleRate: 0.5,
        });
      }).catch(() => {});
    }, 3000);
  };
  if (document.readyState === 'complete') initSentry();
  else window.addEventListener('load', initSentry, { once: true });
}

// Set platform class synchronously BEFORE React mounts (for safe area CSS)
if (Capacitor.isNativePlatform()) {
  document.body.classList.add('capacitor-ios');
}

function mountApp() {
  ReactDOM.createRoot(document.getElementById('root')).render(
    <React.StrictMode>
      <BrowserRouter>
        <App />
      </BrowserRouter>
    </React.StrictMode>
  );

  // Non-blocking native init (status bar, keyboard, splash, IAP)
  // Hydration already done above — initNative skips it if localStorage is populated
  initNative().catch((err) => console.warn('initNative error:', err));

  // Register service worker for PWA
  if ('serviceWorker' in navigator && import.meta.env.PROD) {
    window.addEventListener('load', () => {
      navigator.serviceWorker.register('/sw.js').then(
        (reg) => { if (import.meta.env.DEV) console.log('[SW] Registered:', reg.scope) },
        (err) => console.warn('[SW] Registration failed:', err)
      );
    });
  }
}

// On native iOS/Android: hydrate auth tokens from Capacitor Preferences into
// localStorage BEFORE React mounts. This prevents the race condition where
// RootGate reads an empty localStorage and redirects to login even though
// the user has a valid session stored in native Preferences.
// Hydration is fast (3 key reads), but capped at 2s to prevent hangs.
if (Capacitor.isNativePlatform()) {
  const HYDRATE_TIMEOUT = 2000;
  Promise.race([
    hydrateFromNative(),
    new Promise(resolve => setTimeout(resolve, HYDRATE_TIMEOUT)),
  ])
    .catch((err) => console.warn('Pre-mount hydration failed:', err))
    .finally(mountApp);
} else {
  mountApp();
}
