const THEME_KEYS = Object.keys(THEMES);

const STORAGE_KEY = 'aura-theme';

// ---------------------------------------------------------------------------
// Context
// ---------------------------------------------------------------------------
const ThemeContext = createContext(null);

// ---------------------------------------------------------------------------
// Provider
// ---------------------------------------------------------------------------
export function ThemeProvider({ children }) {
  const [themeKey, setThemeKey] = useState(() => {
    try {
      const stored = localStorage.getItem(STORAGE_KEY);
      if (stored && THEMES[stored]) return stored;
    } catch { /* ignore */ }
    return 'night';
  });

  const currentTheme = THEMES[themeKey] || THEMES.night;
  const { colors } = currentTheme;

  // Persist to localStorage
  useEffect(() => {
    try {
      localStorage.setItem(STORAGE_KEY, themeKey);
    } catch { /* ignore */ }
  }, [themeKey]);

  // Apply CSS custom properties and data-theme attribute to :root
  useEffect(() => {
    const root = document.documentElement;
    // Set data-theme for CSS selector-based theming (themes.css)
    root.setAttribute('data-theme', themeKey);
    // Also set individual CSS custom properties for inline style usage
    Object.entries(colors).forEach(([key, value]) => {
      const cssKey = key.replace(/([A-Z])/g, '-$1').toLowerCase();
      root.style.setProperty(`--color-${cssKey}`, value);
      root.style.setProperty(`--color-${key}`, value);
    });
  }, [themeKey, colors]);

  const value = useMemo(
    () => ({
      theme: themeKey,
      setTheme: (key) => {
        if (THEMES[key]) setThemeKey(key);
      },
      colors,
      themes: THEMES,
      themeKeys: THEME_KEYS,
    }),
    [themeKey, colors],
  );

  return (
    <ThemeContext.Provider value={value}>
      {children}
    </ThemeContext.Provider>
  );
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------
export function useTheme() {
  const ctx = useContext(ThemeContext);
  if (!ctx) {
    throw new Error('useTheme must be used within a <ThemeProvider>');
  }
  return ctx;
}

export { THEMES, THEME_KEYS };
export default ThemeContext;
